const FILES = {
  "server.js": "/**\n * LandGuard NG — Complete Server (Fixed Admin Auth)\n * Zero dependencies — built-in Node.js modules only\n * Run: node server.js\n * Open: http://localhost:3000\n */\n\nconst http   = require('http');\nconst fs     = require('fs');\nconst path   = require('path');\nconst url    = require('url');\nconst crypto = require('crypto');\n\nconst PORT        = process.env.PORT || 3000;\nconst DATA_FILE   = path.join(__dirname, 'data.json');\nconst UPLOADS_DIR = path.join(__dirname, 'uploads');\n\n// Admin credentials — change these to your own\nconst ADMIN_USER  = 'david';\nconst ADMIN_PASS  = 'landguard2026';\n\n// Create uploads folder if needed\nif (!fs.existsSync(UPLOADS_DIR)) fs.mkdirSync(UPLOADS_DIR);\n\n// ── Data helpers ──────────────────────────────────────────────\nfunction readData() {\n  try { return JSON.parse(fs.readFileSync(DATA_FILE, 'utf8')); }\n  catch { return { users: [], sessions: {}, adminSessions: {}, reports: [], consultations: [] }; }\n}\nfunction writeData(d) {\n  fs.writeFileSync(DATA_FILE, JSON.stringify(d, null, 2), 'utf8');\n}\nfunction genId(p)    { return p + '-' + Date.now() + '-' + crypto.randomBytes(3).toString('hex').toUpperCase(); }\nfunction genToken()  { return crypto.randomBytes(32).toString('hex'); }\nfunction hashPw(pw, salt) { return crypto.createHmac('sha256', salt).update(pw).digest('hex'); }\n\n// ── Auth helpers ──────────────────────────────────────────────\nfunction getToken(req) {\n  const auth = req.headers['authorization'] || '';\n  if (auth.startsWith('Bearer ')) return auth.slice(7);\n  const m = (req.headers['cookie'] || '').match(/lg_token=([a-f0-9]+)/);\n  return m ? m[1] : null;\n}\nfunction getUser(token) {\n  if (!token) return null;\n  const d = readData(), s = d.sessions[token];\n  if (!s) return null;\n  if (Date.now() - s.createdAt > 24 * 3600000) { delete d.sessions[token]; writeData(d); return null; }\n  return d.users.find(u => u.id === s.userId) || null;\n}\nfunction requireAuth(req, res) {\n  const u = getUser(getToken(req));\n  if (!u) { sendJSON(res, 401, { error: 'Please log in.' }); return null; }\n  return u;\n}\n\n// ── Response helpers ──────────────────────────────────────────\nfunction sendJSON(res, code, payload, extra = {}) {\n  const body = JSON.stringify(payload);\n  res.writeHead(code, { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body), 'Access-Control-Allow-Origin': '*', 'Access-Control-Allow-Headers': 'Content-Type,Authorization', ...extra });\n  res.end(body);\n}\nfunction sendFile(res, fp, extra = {}) {\n  const mime = { '.html': 'text/html', '.css': 'text/css', '.js': 'application/javascript', '.json': 'application/json', '.ico': 'image/x-icon', '.png': 'image/png', '.jpg': 'image/jpeg', '.jpeg': 'image/jpeg', '.pdf': 'application/pdf', '.gif': 'image/gif', '.webp': 'image/webp' };\n  fs.readFile(fp, (err, data) => {\n    if (err) { res.writeHead(404, { 'Content-Type': 'text/plain' }); return res.end('Not Found'); }\n    res.writeHead(200, { 'Content-Type': mime[path.extname(fp)] || 'text/plain', ...extra });\n    res.end(data);\n  });\n}\nfunction parseBody(req) {\n  return new Promise((resolve, reject) => {\n    let b = '';\n    req.on('data', c => { b += c; if (b.length > 10 * 1024 * 1024) reject(new Error('Too large')); });\n    req.on('end', () => { try { resolve(JSON.parse(b || '{}')); } catch { reject(new Error('Bad JSON')); } });\n    req.on('error', reject);\n  });\n}\n\n// ── AUTH ROUTES ───────────────────────────────────────────────\nasync function handleRegister(req, res) {\n  let b; try { b = await parseBody(req); } catch { return sendJSON(res, 400, { error: 'Invalid request' }); }\n  const { username, password, fullName, phone } = b;\n  if (!username || !password) return sendJSON(res, 400, { error: 'Username and password are required.' });\n  if (username.length < 3)    return sendJSON(res, 400, { error: 'Username must be at least 3 characters.' });\n  if (password.length < 6)    return sendJSON(res, 400, { error: 'Password must be at least 6 characters.' });\n  if (!phone)                  return sendJSON(res, 400, { error: 'Phone number is required.' });\n  const d = readData();\n  if (!d.adminSessions) d.adminSessions = {};\n  if (d.users.find(u => u.username.toLowerCase() === username.toLowerCase()))\n    return sendJSON(res, 409, { error: 'Username already taken.' });\n  const salt = crypto.randomBytes(16).toString('hex');\n  const token = genToken();\n  const user = { id: genId('USR'), username: username.trim(), fullName: (fullName||'').trim(), phone: phone.trim(), salt, password: hashPw(password, salt), createdAt: new Date().toISOString() };\n  d.users.push(user);\n  d.sessions[token] = { userId: user.id, createdAt: Date.now() };\n  writeData(d);\n  console.log(`[REGISTER] ${username}`);\n  sendJSON(res, 200, { message: 'Account created! Welcome to LandGuard NG.', token, username: user.username, fullName: user.fullName, phone: user.phone }, { 'Set-Cookie': `lg_token=${token}; Path=/; HttpOnly; Max-Age=${24*3600}` });\n}\n\nasync function handleLogin(req, res) {\n  let b; try { b = await parseBody(req); } catch { return sendJSON(res, 400, { error: 'Invalid request' }); }\n  const { username, password } = b;\n  if (!username || !password) return sendJSON(res, 400, { error: 'Username and password are required.' });\n  const d = readData();\n  const user = d.users.find(u => u.username.toLowerCase() === username.toLowerCase());\n  if (!user || hashPw(password, user.salt) !== user.password) return sendJSON(res, 401, { error: 'Invalid username or password.' });\n  const token = genToken();\n  if (!d.adminSessions) d.adminSessions = {};\n  d.sessions[token] = { userId: user.id, createdAt: Date.now() };\n  writeData(d);\n  console.log(`[LOGIN] ${username}`);\n  sendJSON(res, 200, { message: `Welcome back, ${user.fullName || user.username}!`, token, username: user.username, fullName: user.fullName, phone: user.phone || '' }, { 'Set-Cookie': `lg_token=${token}; Path=/; HttpOnly; Max-Age=${24*3600}` });\n}\n\nfunction handleLogout(req, res) {\n  const token = getToken(req);\n  if (token) { const d = readData(); delete d.sessions[token]; writeData(d); }\n  sendJSON(res, 200, { message: 'Logged out.' }, { 'Set-Cookie': 'lg_token=; Path=/; Expires=Thu, 01 Jan 1970 00:00:00 GMT' });\n}\n\nfunction handleMe(req, res) {\n  const u = getUser(getToken(req));\n  if (!u) return sendJSON(res, 401, { error: 'Not logged in.' });\n  sendJSON(res, 200, { username: u.username, fullName: u.fullName, phone: u.phone || '' });\n}\n\n// ── PROTECTED ROUTES ──────────────────────────────────────────\nfunction handleStats(req, res) {\n  const u = requireAuth(req, res); if (!u) return;\n  const d = readData();\n  sendJSON(res, 200, { totalReports: d.reports.length, totalConsultations: d.consultations.length });\n}\n\nasync function handleReport(req, res) {\n  const u = requireAuth(req, res); if (!u) return;\n  let b; try { b = await parseBody(req); } catch { return sendJSON(res, 400, { error: 'Invalid request' }); }\n  if (!b.location || !b.issue) return sendJSON(res, 400, { error: 'Location and issue are required.' });\n\n  // Save evidence file\n  let evidenceFile = null;\n  if (b.evidenceBase64 && b.evidenceName) {\n    try {\n      const ext = path.extname(b.evidenceName).toLowerCase();\n      if (['.jpg','.jpeg','.png','.gif','.webp','.pdf'].includes(ext)) {\n        const fname = 'evidence-' + Date.now() + '-' + crypto.randomBytes(4).toString('hex') + ext;\n        fs.writeFileSync(path.join(UPLOADS_DIR, fname), Buffer.from(b.evidenceBase64.replace(/^data:[^;]+;base64,/, ''), 'base64'));\n        evidenceFile = fname;\n      }\n    } catch(e) { console.error('Evidence save error:', e.message); }\n  }\n\n  const d = readData();\n  if (!d.adminSessions) d.adminSessions = {};\n  const reportId = genId('RPT');\n  d.reports.push({ reportId, submittedBy: u.username, location: b.location.trim(), agent: (b.agent||'').trim(), reporterName: (b.reporterName||u.username).trim(), reporterEmail: (b.reporterEmail||'').trim(), phone: (b.phone||'').trim(), issue: b.issue.trim(), evidenceFile, status: 'Pending Review', submittedAt: new Date().toISOString() });\n  writeData(d);\n  console.log(`[REPORT] ${reportId} by ${u.username}`);\n  sendJSON(res, 200, { message: 'Report submitted!', reportId, hasEvidence: !!evidenceFile });\n}\n\nasync function handleConsult(req, res) {\n  const u = requireAuth(req, res); if (!u) return;\n  let b; try { b = await parseBody(req); } catch { return sendJSON(res, 400, { error: 'Invalid request' }); }\n  if (!b.name || !b.email) return sendJSON(res, 400, { error: 'Name and email are required.' });\n  const d = readData();\n  if (!d.adminSessions) d.adminSessions = {};\n  const consultId = genId('CONS');\n  d.consultations.push({ consultId, submittedBy: u.username, name: b.name.trim(), email: b.email.trim(), phone: (b.phone||'').trim(), service: (b.service||'General Inquiry').trim(), message: (b.message||'').trim(), status: 'Awaiting Callback', submittedAt: new Date().toISOString() });\n  writeData(d);\n  console.log(`[CONSULT] ${consultId} by ${u.username}`);\n  sendJSON(res, 200, { message: `Thank you ${b.name.trim()}! We'll reach out within 24 hours.`, consultId });\n}\n\n// ── ADMIN SESSIONS (persisted in data.json) ───────────────────\nconst ADMIN_SESSION_TTL = 8 * 3600 * 1000; // 8 hours\n\nfunction genAdminToken() {\n  const t = crypto.randomBytes(24).toString('hex');\n  const d = readData();\n  if (!d.adminSessions) d.adminSessions = {};\n  // Clean up expired sessions first\n  const now = Date.now();\n  for (const [k, v] of Object.entries(d.adminSessions)) {\n    if (now - v.createdAt > ADMIN_SESSION_TTL) delete d.adminSessions[k];\n  }\n  d.adminSessions[t] = { createdAt: now };\n  writeData(d);\n  return t;\n}\n\nfunction checkAdminSession(req) {\n  const m = (req.headers['cookie'] || '').match(/lg_admin=([a-f0-9]+)/);\n  if (!m) return false;\n  const token = m[1];\n  const d = readData();\n  if (!d.adminSessions || !d.adminSessions[token]) return false;\n  // Check expiry\n  if (Date.now() - d.adminSessions[token].createdAt > ADMIN_SESSION_TTL) {\n    delete d.adminSessions[token];\n    writeData(d);\n    return false;\n  }\n  return true;\n}\n\nfunction handleAdminLogout(req, res) {\n  const m = (req.headers['cookie'] || '').match(/lg_admin=([a-f0-9]+)/);\n  if (m) {\n    const d = readData();\n    if (d.adminSessions) delete d.adminSessions[m[1]];\n    writeData(d);\n  }\n  res.writeHead(302, {\n    'Location': '/admin/login',\n    'Set-Cookie': 'lg_admin=; Path=/; Expires=Thu, 01 Jan 1970 00:00:00 GMT'\n  });\n  res.end();\n}\n\n// ── ADMIN LOGIN PAGE ─────────────────────────────────────────\nfunction handleAdminLogin(req, res) {\n  // If already logged in, redirect to dashboard\n  if (checkAdminSession(req)) {\n    res.writeHead(302, { Location: '/admin' }); return res.end();\n  }\n  const loginPage = `<!DOCTYPE html><html lang=\"en\"><head><meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"><title>LandGuard Admin — Login</title>\n<style>\n*{margin:0;padding:0;box-sizing:border-box}\nbody{font-family:system-ui,sans-serif;background:#0a1f14;display:flex;align-items:center;justify-content:center;min-height:100vh;padding:20px}\nbody::before{content:'';position:fixed;inset:0;background:radial-gradient(ellipse 70% 60% at 70% 30%,rgba(26,122,74,.25) 0%,transparent 60%);pointer-events:none}\n.card{background:#fff;border-radius:16px;width:100%;max-width:400px;padding:44px;box-shadow:0 30px 80px rgba(0,0,0,.5);position:relative;z-index:1}\n.logo{display:flex;align-items:center;gap:10px;justify-content:center;margin-bottom:28px}\n.logo-icon{width:42px;height:42px;border-radius:10px;background:linear-gradient(135deg,#c9a84c,#1a7a4a);display:flex;align-items:center;justify-content:center;font-size:20px}\n.logo-text{font-size:20px;font-weight:700;color:#0a1f14}\n.logo-text span{color:#1a7a4a}\nh2{font-size:22px;color:#0a1f14;margin-bottom:6px;text-align:center}\np{font-size:14px;color:#6b7280;text-align:center;margin-bottom:28px}\n.field{margin-bottom:16px}\nlabel{display:block;font-size:13px;font-weight:600;color:#0a1f14;margin-bottom:6px}\ninput{width:100%;padding:13px 16px;background:#fafaf5;border:1.5px solid #e5e7eb;border-radius:8px;font-size:15px;outline:none;transition:border-color .2s}\ninput:focus{border-color:#1a7a4a;box-shadow:0 0 0 3px rgba(26,122,74,.1)}\nbutton{width:100%;padding:14px;background:linear-gradient(135deg,#145c38,#1a7a4a);color:#fff;border:none;border-radius:8px;font-size:16px;font-weight:600;cursor:pointer;margin-top:8px;transition:all .2s}\nbutton:hover{transform:translateY(-2px);box-shadow:0 8px 25px rgba(20,92,56,.4)}\nbutton:disabled{opacity:.6;cursor:not-allowed;transform:none}\n.err{background:#fef2f2;color:#ef4444;border:1px solid #fecaca;border-radius:8px;padding:12px 16px;font-size:14px;margin-bottom:16px;display:none}\n.err.show{display:block}\n.badge{background:#fff8e6;border:1px solid #f0d98a;border-radius:8px;padding:10px 14px;font-size:13px;color:#7a5c00;text-align:center;margin-bottom:20px}\n</style></head><body>\n<div class=\"card\">\n  <div class=\"logo\"><div class=\"logo-icon\">🛡</div><span class=\"logo-text\">Land<span>Guard</span> NG</span></div>\n  <h2>Admin Access</h2>\n  <p>Enter your admin credentials to continue</p>\n  <div class=\"badge\">🔒 This area is restricted to administrators only</div>\n  <div class=\"err\" id=\"err\">Wrong username or password. Access denied.</div>\n  <form id=\"form\">\n    <div class=\"field\"><label>Username</label><input type=\"text\" id=\"u\" placeholder=\"Admin username\" required autofocus></div>\n    <div class=\"field\"><label>Password</label><input type=\"password\" id=\"p\" placeholder=\"Admin password\" required></div>\n    <button type=\"submit\" id=\"btn\">Sign In to Dashboard</button>\n  </form>\n</div>\n<script>\ndocument.getElementById('form').addEventListener('submit',async e=>{\n  e.preventDefault();\n  const btn=document.getElementById('btn');\n  btn.disabled=true;btn.textContent='Verifying...';\n  const r=await fetch('/api/admin/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({username:document.getElementById('u').value,password:document.getElementById('p').value})});\n  if(r.ok){window.location.href='/admin';}\n  else{document.getElementById('err').classList.add('show');btn.disabled=false;btn.textContent='Sign In to Dashboard';}\n});\n</script>\n</body></html>`;\n  res.writeHead(200, { 'Content-Type': 'text/html' }); res.end(loginPage);\n}\n\nasync function handleAdminLoginPost(req, res) {\n  let b; try { b = await parseBody(req); } catch { return sendJSON(res, 400, { error: 'Bad request' }); }\n  if (b.username !== ADMIN_USER || b.password !== ADMIN_PASS) {\n    console.log(`[ADMIN] ❌ Failed login attempt — username: \"${b.username}\"`);\n    return sendJSON(res, 401, { error: 'Wrong credentials' });\n  }\n  const t = genAdminToken();\n  console.log(`[ADMIN] ✅ Admin logged in`);\n  sendJSON(res, 200, { ok: true }, { 'Set-Cookie': `lg_admin=${t}; Path=/; HttpOnly; Max-Age=${8*3600}` });\n}\n\n// ── ADMIN DASHBOARD ───────────────────────────────────────────\nfunction handleAdmin(req, res) {\n  if (!checkAdminSession(req)) {\n    res.writeHead(302, { Location: '/admin/login' }); return res.end();\n  }\n  const d = readData();\n  const html = `<!DOCTYPE html><html lang=\"en\"><head><meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"><title>LandGuard NG Admin</title>\n<style>\n*{margin:0;padding:0;box-sizing:border-box}\nbody{font-family:system-ui,sans-serif;background:#0a1f14;color:#e5e7eb;padding:24px}\n.top-bar{display:flex;align-items:center;justify-content:space-between;margin-bottom:4px}\nh1{color:#c9a84c;font-size:22px}\n.logout-btn{background:#1a3a26;border:1px solid #ef4444;color:#ef4444;padding:8px 18px;border-radius:8px;cursor:pointer;font-size:14px;font-weight:600;transition:all .2s}\n.logout-btn:hover{background:#ef4444;color:#fff}\n.meta{color:#6b7280;font-size:13px;margin-bottom:28px}\nh2{color:#22c55e;margin:36px 0 10px;font-size:16px}\n.stats{display:flex;gap:20px;margin-bottom:32px;flex-wrap:wrap}\n.stat-box{background:#0d3322;border-radius:10px;padding:18px 26px;border:1px solid #1a3a26;min-width:120px}\n.stat-num{font-size:28px;font-weight:700;color:#c9a84c;font-family:Georgia,serif}\n.stat-label{font-size:11px;color:#6b7280;margin-top:4px;text-transform:uppercase;letter-spacing:1px}\n.table-wrap{overflow-x:auto;margin-bottom:32px}\ntable{border-collapse:collapse;width:100%;font-size:12px;min-width:600px}\nth{background:#145c38;color:#fff;padding:9px 12px;text-align:left;white-space:nowrap}\ntd{padding:8px 12px;border-bottom:1px solid #1a3a26;vertical-align:top;max-width:240px;word-break:break-word}\ntr:hover td{background:#0d2c1c}\n.badge{display:inline-block;padding:2px 8px;border-radius:4px;font-size:11px;background:#1a7a4a;color:#fff}\na{color:#c9a84c}\n.empty{text-align:center;color:#6b7280;padding:28px}\n</style></head><body>\n<div class=\"top-bar\">\n  <h1>🛡 LandGuard NG — Admin Dashboard</h1>\n  <button class=\"logout-btn\" onclick=\"if(confirm('Sign out of admin?')) window.location.href='/admin/logout'\">🚪 Sign Out</button>\n</div>\n<p class=\"meta\">Last refreshed: ${new Date().toLocaleString('en-NG')} &nbsp;|&nbsp; <a href=\"/admin\" style=\"color:#c9a84c\">↻ Refresh</a></p>\n<div class=\"stats\">\n  <div class=\"stat-box\"><div class=\"stat-num\">${d.reports.length}</div><div class=\"stat-label\">Reports</div></div>\n  <div class=\"stat-box\"><div class=\"stat-num\">${d.consultations.length}</div><div class=\"stat-label\">Consultations</div></div>\n  <div class=\"stat-box\"><div class=\"stat-num\">${d.users.length}</div><div class=\"stat-label\">Users</div></div>\n</div>\n\n<h2>👥 Registered Users (${d.users.length})</h2>\n<div class=\"table-wrap\"><table><tr><th>#</th><th>Username</th><th>Full Name</th><th>Phone</th><th>Joined</th></tr>\n${d.users.map((u,i)=>`<tr><td>${i+1}</td><td>${u.username}</td><td>${u.fullName||'—'}</td><td>${u.phone||'—'}</td><td>${new Date(u.createdAt).toLocaleString('en-NG')}</td></tr>`).join('')||`<tr><td colspan=\"5\" class=\"empty\">No users yet</td></tr>`}\n</table></div>\n\n<h2>📋 Fraud Reports (${d.reports.length})</h2>\n<div class=\"table-wrap\"><table><tr><th>#</th><th>ID</th><th>Location</th><th>Agent</th><th>Reporter</th><th>Phone</th><th>Issue</th><th>Evidence</th><th>By</th><th>Date</th><th>Status</th></tr>\n${d.reports.slice().reverse().map((r,i)=>`<tr><td>${i+1}</td><td style=\"font-size:10px\">${r.reportId}</td><td>${r.location}</td><td>${r.agent||'—'}</td><td>${r.reporterName}</td><td>${r.phone||'—'}</td><td>${(r.issue||'').slice(0,80)}${r.issue&&r.issue.length>80?'…':''}</td><td>${r.evidenceFile?`<a href=\"/uploads/${r.evidenceFile}\" target=\"_blank\">View 🖼</a>`:'—'}</td><td>${r.submittedBy||'—'}</td><td style=\"font-size:10px\">${new Date(r.submittedAt).toLocaleString('en-NG')}</td><td><span class=\"badge\">${r.status}</span></td></tr>`).join('')||`<tr><td colspan=\"11\" class=\"empty\">No reports yet</td></tr>`}\n</table></div>\n\n<h2>📅 Consultation Requests (${d.consultations.length})</h2>\n<div class=\"table-wrap\"><table><tr><th>#</th><th>ID</th><th>Name</th><th>Email</th><th>Phone</th><th>Service</th><th>Message</th><th>By</th><th>Date</th><th>Status</th></tr>\n${d.consultations.slice().reverse().map((c,i)=>`<tr><td>${i+1}</td><td style=\"font-size:10px\">${c.consultId}</td><td>${c.name}</td><td>${c.email}</td><td>${c.phone||'—'}</td><td>${c.service}</td><td>${(c.message||'—').slice(0,60)}${(c.message||'').length>60?'…':''}</td><td>${c.submittedBy||'—'}</td><td style=\"font-size:10px\">${new Date(c.submittedAt).toLocaleString('en-NG')}</td><td><span class=\"badge\">${c.status}</span></td></tr>`).join('')||`<tr><td colspan=\"10\" class=\"empty\">No consultations yet</td></tr>`}\n</table></div>\n</body></html>`;\n  res.writeHead(200, { 'Content-Type': 'text/html' }); res.end(html);\n}\n\n// ── ROUTER ────────────────────────────────────────────────────\nconst server = http.createServer(async (req, res) => {\n  const { pathname } = url.parse(req.url);\n  const method = req.method.toUpperCase();\n  if (method === 'OPTIONS') { res.writeHead(204, { 'Access-Control-Allow-Origin': '*', 'Access-Control-Allow-Methods': 'GET,POST,OPTIONS', 'Access-Control-Allow-Headers': 'Content-Type,Authorization' }); return res.end(); }\n  console.log(`${method} ${pathname}`);\n  if (pathname === '/api/auth/register' && method === 'POST') return handleRegister(req, res);\n  if (pathname === '/api/auth/login'    && method === 'POST') return handleLogin(req, res);\n  if (pathname === '/api/auth/logout'   && method === 'POST') return handleLogout(req, res);\n  if (pathname === '/api/auth/me'       && method === 'GET')  return handleMe(req, res);\n  if (pathname === '/api/stats'         && method === 'GET')  return handleStats(req, res);\n  if (pathname === '/api/report'        && method === 'POST') return handleReport(req, res);\n  if (pathname === '/api/consult'       && method === 'POST') return handleConsult(req, res);\n  if (pathname === '/admin/login'  && method === 'GET')  return handleAdminLogin(req, res);\n  if (pathname === '/admin/logout' && method === 'GET')  return handleAdminLogout(req, res);\n  if (pathname === '/api/admin/login' && method === 'POST') return handleAdminLoginPost(req, res);\n  if (pathname === '/admin'        && method === 'GET')  return handleAdmin(req, res);\n  if (pathname.startsWith('/uploads/')) {\n    const fp = path.join(UPLOADS_DIR, path.basename(pathname));\n    return fs.existsSync(fp) ? sendFile(res, fp) : (res.writeHead(404), res.end('Not found'));\n  }\n  if (pathname === '/login' || pathname === '/login.html') return sendFile(res, path.join(__dirname, 'login.html'));\n  if (pathname === '/' || pathname === '/index.html')      return sendFile(res, path.join(__dirname, 'index.html'));\n  const fp = path.join(__dirname, pathname.replace(/^\\//, ''));\n  if (fs.existsSync(fp) && fs.statSync(fp).isFile()) return sendFile(res, fp);\n  res.writeHead(404, { 'Content-Type': 'text/plain' }); res.end('Not found');\n});\n\nserver.listen(PORT, () => {\n  console.log('\\n  ╔══════════════════════════════════════════╗');\n  console.log('  ║   🛡  LandGuard NG — Server Started!    ║');\n  console.log('  ╚══════════════════════════════════════════╝');\n  console.log(`\\n  🌐  Website : http://localhost:${PORT}`);\n  console.log(`  📊  Admin   : http://localhost:${PORT}/admin`);\n  console.log(`  📁  Data    : ${DATA_FILE}`);\n  console.log('\\n  Press Ctrl+C to stop.\\n');\n});\n",
  "index.html": "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>LandGuard NG — Buy Land Safely in Nigeria</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,500;0,700;1,500&family=DM+Sans:wght@300;400;500;600&display=swap\" rel=\"stylesheet\">\n<style>\n:root{--ink:#0a1f14;--forest:#0d3322;--emerald:#145c38;--jade:#1a7a4a;--mint:#22c55e;--gold:#c9a84c;--gold-lt:#f0d98a;--cream:#fafaf5;--parchment:#f3efe0;--white:#fff;--muted:#6b7280;--border:rgba(255,255,255,.1);--shadow:0 20px 60px rgba(10,31,20,.18);--r:10px;--fh:'Playfair Display',Georgia,serif;--fb:'DM Sans',system-ui,sans-serif}\n*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}\nhtml{scroll-behavior:smooth}\nbody{background:var(--cream);color:var(--ink);font-family:var(--fb);font-size:16px;line-height:1.7;overflow-x:hidden}\n::-webkit-scrollbar{width:6px}::-webkit-scrollbar-track{background:var(--cream)}::-webkit-scrollbar-thumb{background:var(--jade);border-radius:99px}\n\n/* Header */\nheader{position:sticky;top:0;z-index:900;background:rgba(10,31,20,.95);backdrop-filter:blur(16px);border-bottom:1px solid var(--border);padding:0 6%;display:flex;align-items:center;justify-content:space-between;height:70px}\n.logo{display:flex;align-items:center;gap:10px;text-decoration:none}\n.logo-icon{width:38px;height:38px;border-radius:8px;background:linear-gradient(135deg,var(--gold),var(--jade));display:flex;align-items:center;justify-content:center;font-size:18px}\n.logo-text{font-family:var(--fh);font-size:19px;font-weight:700;color:var(--white);letter-spacing:.3px}\n.logo-text span{color:var(--gold)}\nnav{display:flex;align-items:center;gap:4px}\nnav a{color:rgba(255,255,255,.75);padding:8px 14px;border-radius:6px;text-decoration:none;font-size:14px;font-weight:500;transition:all .2s}\nnav a:hover{color:var(--white);background:rgba(255,255,255,.1)}\n.nav-cta{background:linear-gradient(135deg,var(--gold),#a8803a)!important;color:var(--ink)!important;font-weight:600!important;padding:8px 18px!important}\n.nav-cta:hover{transform:translateY(-1px);box-shadow:0 4px 15px rgba(201,168,76,.4)}\n.user-pill{display:flex;align-items:center;gap:10px;background:rgba(255,255,255,.08);border:1px solid rgba(255,255,255,.15);border-radius:99px;padding:6px 16px 6px 8px}\n.user-avatar{width:28px;height:28px;border-radius:50%;background:linear-gradient(135deg,var(--gold),var(--emerald));display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:700;color:var(--ink)}\n.user-name{font-size:13px;font-weight:600;color:var(--white)}\n.logout-btn{background:none;border:none;cursor:pointer;color:rgba(255,255,255,.5);font-size:13px;padding:4px 8px;border-radius:6px;transition:all .2s;font-family:var(--fb);font-weight:500}\n.logout-btn:hover{color:#ef4444;background:rgba(239,68,68,.1)}\n.hamburger{display:none;flex-direction:column;gap:5px;cursor:pointer;padding:4px}\n.hamburger span{width:22px;height:2px;background:var(--white);border-radius:99px;transition:.3s}\n\n/* Hero */\n.hero{position:relative;overflow:hidden;background:var(--forest);padding:110px 6% 100px;min-height:92vh;display:flex;align-items:center}\n.hero-bg{position:absolute;inset:0;pointer-events:none;background:radial-gradient(ellipse 80% 60% at 70% 50%,rgba(26,122,74,.25) 0%,transparent 60%),radial-gradient(ellipse 40% 40% at 15% 80%,rgba(201,168,76,.12) 0%,transparent 50%),linear-gradient(160deg,var(--forest) 0%,var(--ink) 100%)}\n.hero-grid{position:absolute;inset:0;pointer-events:none;opacity:.06;background-image:linear-gradient(rgba(255,255,255,.4) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.4) 1px,transparent 1px);background-size:60px 60px}\n#hero-canvas{position:absolute;inset:0;width:100%;height:100%;pointer-events:none;opacity:.55}\n.hero-content{position:relative;max-width:700px}\n.hero-badge{display:inline-flex;align-items:center;gap:8px;background:rgba(201,168,76,.15);border:1px solid rgba(201,168,76,.3);color:var(--gold-lt);padding:6px 16px;border-radius:99px;font-size:13px;font-weight:500;margin-bottom:30px;animation:fadeUp .6s ease both}\n.hero h1{font-family:var(--fh);font-size:clamp(38px,6vw,68px);line-height:1.1;color:var(--white);margin-bottom:24px;animation:fadeUp .6s .1s ease both}\n.hero h1 em{color:var(--gold);font-style:italic}\n.hero p{font-size:clamp(16px,2vw,18px);color:rgba(255,255,255,.72);max-width:560px;margin-bottom:44px;font-weight:300;animation:fadeUp .6s .2s ease both}\n.hero-actions{display:flex;gap:14px;flex-wrap:wrap;animation:fadeUp .6s .3s ease both}\n.btn{display:inline-flex;align-items:center;gap:8px;padding:14px 28px;border-radius:8px;font-family:var(--fb);font-size:15px;font-weight:600;cursor:pointer;border:none;text-decoration:none;transition:all .22s}\n.btn-gold{background:linear-gradient(135deg,var(--gold) 0%,#a8803a 100%);color:var(--ink);box-shadow:0 4px 20px rgba(201,168,76,.35)}\n.btn-gold:hover{transform:translateY(-2px);box-shadow:0 8px 30px rgba(201,168,76,.45)}\n.btn-outline{background:transparent;color:var(--white);border:1.5px solid rgba(255,255,255,.35)}\n.btn-outline:hover{background:rgba(255,255,255,.08);border-color:rgba(255,255,255,.6)}\n.hero-stats{position:absolute;bottom:48px;right:6%;display:flex;gap:40px;animation:fadeUp .6s .4s ease both}\n.stat{text-align:center}\n.stat-num{font-family:var(--fh);font-size:32px;font-weight:700;color:var(--gold);line-height:1}\n.stat-label{font-size:12px;color:rgba(255,255,255,.55);margin-top:4px;font-weight:500;letter-spacing:.8px;text-transform:uppercase}\n\n/* Sections */\n.section{padding:90px 6%}\n.section-alt{background:var(--parchment)}\n.section-label{font-size:12px;font-weight:600;letter-spacing:2px;text-transform:uppercase;color:var(--jade);margin-bottom:12px}\n.section-title{font-family:var(--fh);font-size:clamp(28px,4vw,42px);color:var(--ink);line-height:1.15;margin-bottom:16px}\n.section-sub{font-size:17px;color:var(--muted);max-width:560px;font-weight:300}\n.section-header{margin-bottom:56px}\n\n/* Checklist */\n.checklist-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:20px}\n.check-card{background:var(--white);border:1px solid #e5e7eb;border-radius:var(--r);padding:28px;display:flex;gap:16px;align-items:flex-start;box-shadow:0 2px 8px rgba(0,0,0,.04);transition:all .25s;opacity:0;transform:translateY(20px)}\n.check-card.visible{opacity:1;transform:none}\n.check-card:hover{transform:translateY(-3px);box-shadow:0 10px 30px rgba(0,0,0,.08);border-color:var(--mint)}\n.check-icon{width:40px;height:40px;flex-shrink:0;background:linear-gradient(135deg,var(--emerald),var(--jade));border-radius:8px;display:flex;align-items:center;justify-content:center;color:var(--white);font-size:18px}\n.check-body{flex:1}\n.check-step{font-size:11px;font-weight:600;color:var(--jade);letter-spacing:1px;text-transform:uppercase;margin-bottom:4px}\n.check-title{font-weight:600;color:var(--ink);margin-bottom:4px}\n.check-desc{font-size:14px;color:var(--muted);line-height:1.5}\n\n/* Docs */\n.docs-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:24px}\n.doc-card{background:var(--forest);border-radius:var(--r);padding:32px;border:1px solid rgba(255,255,255,.08);transition:all .25s;opacity:0;transform:translateY(20px)}\n.doc-card.visible{opacity:1;transform:none}\n.doc-card:hover{transform:translateY(-3px);border-color:rgba(201,168,76,.4)}\n.doc-tag{display:inline-block;background:rgba(201,168,76,.2);color:var(--gold-lt);font-size:11px;font-weight:600;padding:4px 10px;border-radius:4px;margin-bottom:16px;letter-spacing:.8px;text-transform:uppercase}\n.doc-card h4{font-family:var(--fh);font-size:20px;color:var(--white);margin-bottom:12px}\n.doc-card p{font-size:14px;color:rgba(255,255,255,.65);line-height:1.6}\n\n/* Forms */\n.form-wrapper{max-width:680px;margin:0 auto;background:var(--white);border-radius:16px;border:1px solid #e5e7eb;padding:48px;box-shadow:var(--shadow)}\n.form-wrapper h3{font-family:var(--fh);font-size:28px;color:var(--ink);margin-bottom:8px}\n.form-wrapper .sub{color:var(--muted);font-size:15px;margin-bottom:36px;font-weight:300}\n.form-row{display:grid;grid-template-columns:1fr 1fr;gap:16px}\n@media(max-width:600px){.form-row{grid-template-columns:1fr}}\n.field{margin-bottom:20px}\n.field label{display:block;font-size:13px;font-weight:600;color:var(--ink);margin-bottom:7px}\n.field input,.field textarea,.field select{width:100%;padding:13px 16px;background:var(--cream);border:1.5px solid #e5e7eb;border-radius:8px;font-family:var(--fb);font-size:15px;color:var(--ink);transition:border-color .2s;outline:none}\n.field input:focus,.field textarea:focus,.field select:focus{border-color:var(--jade);background:var(--white);box-shadow:0 0 0 3px rgba(26,122,74,.1)}\n.field textarea{resize:vertical;min-height:120px}\n.submit-btn{width:100%;padding:16px;background:linear-gradient(135deg,var(--emerald),var(--jade));color:var(--white);border:none;border-radius:8px;font-family:var(--fb);font-size:16px;font-weight:600;cursor:pointer;transition:all .22s;display:flex;align-items:center;justify-content:center;gap:8px}\n.submit-btn:hover{transform:translateY(-2px);box-shadow:0 8px 25px rgba(20,92,56,.35)}\n.submit-btn:disabled{opacity:.6;cursor:not-allowed;transform:none}\n\n/* Upload box */\n.upload-box{border:2px dashed #d1d5db;border-radius:8px;padding:28px;text-align:center;cursor:pointer;transition:all .2s;background:var(--cream)}\n.upload-box:hover{border-color:var(--jade);background:rgba(26,122,74,.04)}\n.upload-box.has-file{border-color:var(--mint);border-style:solid;background:rgba(34,197,94,.05)}\n.upload-icon{font-size:28px;margin-bottom:8px}\n.upload-text{font-size:14px;font-weight:600;color:var(--ink)}\n.upload-hint{font-size:12px;color:var(--muted);margin-top:4px}\n.file-preview{display:none;margin-top:10px;padding:12px 16px;background:var(--cream);border-radius:8px;border:1px solid #e5e7eb;align-items:center;gap:10px}\n.file-preview.show{display:flex}\n\n/* LGA Directory */\n.lga-bar{display:flex;gap:14px;flex-wrap:wrap;margin-bottom:36px}\n.lga-select{flex:1;min-width:200px;padding:13px 16px;background:var(--white);border:1.5px solid #e5e7eb;border-radius:8px;font-family:var(--fb);font-size:15px;color:var(--ink);outline:none;transition:border-color .2s;cursor:pointer}\n.lga-select:focus{border-color:var(--jade);box-shadow:0 0 0 3px rgba(26,122,74,.1)}\n.lga-result{background:var(--white);border:1px solid #e5e7eb;border-radius:12px;padding:32px;box-shadow:0 4px 16px rgba(0,0,0,.06);display:none}\n.lga-result.show{display:block}\n.lga-result h3{font-family:var(--fh);font-size:22px;color:var(--ink);margin-bottom:20px;padding-bottom:14px;border-bottom:2px solid var(--parchment)}\n.lga-contacts{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:16px}\n.contact-card{background:var(--parchment);border-radius:8px;padding:18px;border-left:3px solid var(--jade)}\n.contact-type{font-size:11px;font-weight:600;letter-spacing:1px;text-transform:uppercase;color:var(--jade);margin-bottom:6px}\n.contact-name{font-weight:600;color:var(--ink);margin-bottom:4px}\n.contact-detail{font-size:13px;color:var(--muted);line-height:1.6}\n.contact-detail a{color:var(--jade);text-decoration:none;font-weight:500}\n.contact-detail a:hover{text-decoration:underline}\n.lga-placeholder{text-align:center;padding:48px 20px;color:var(--muted)}\n.lga-placeholder .ph-icon{font-size:48px;margin-bottom:12px}\n.lga-placeholder p{font-size:15px;font-weight:300}\n\n/* Toast */\n#toast{position:fixed;bottom:30px;left:50%;transform:translateX(-50%) translateY(100px);background:var(--forest);color:var(--white);padding:14px 24px;border-radius:10px;font-size:15px;font-weight:500;box-shadow:0 8px 30px rgba(0,0,0,.25);transition:transform .4s cubic-bezier(.34,1.56,.64,1);z-index:9999;white-space:nowrap;border-left:4px solid var(--mint)}\n#toast.success{border-color:var(--mint)}\n#toast.error{border-color:#ef4444}\n#toast.show{transform:translateX(-50%) translateY(0)}\n\n/* CTA strip */\n.cta-strip{background:linear-gradient(135deg,var(--ink) 0%,var(--forest) 60%,var(--emerald) 100%);padding:80px 6%;display:flex;align-items:center;justify-content:space-between;gap:40px;flex-wrap:wrap}\n.cta-strip h2{font-family:var(--fh);font-size:clamp(24px,3.5vw,38px);color:var(--white)}\n.cta-strip p{color:rgba(255,255,255,.7);margin-top:8px;font-weight:300}\n.consult-form-wrap{max-width:720px;margin:0 auto;background:var(--white);border-radius:16px;padding:48px;border:1px solid #e5e7eb;box-shadow:var(--shadow)}\n\n/* About */\n.about-grid{display:grid;grid-template-columns:1fr 1fr;gap:60px;align-items:center}\n@media(max-width:768px){.about-grid{grid-template-columns:1fr}}\n.about-visual{background:linear-gradient(135deg,var(--forest),var(--emerald));border-radius:16px;padding:48px;aspect-ratio:1;display:flex;flex-direction:column;justify-content:center;align-items:center;text-align:center;border:1px solid rgba(255,255,255,.1)}\n.about-visual .big-num{font-family:var(--fh);font-size:72px;line-height:1;background:linear-gradient(135deg,var(--gold),var(--gold-lt));-webkit-background-clip:text;-webkit-text-fill-color:transparent}\n.about-visual p{color:rgba(255,255,255,.7);margin-top:12px;font-size:16px}\n.about-text p{color:var(--muted);margin-bottom:20px;font-weight:300;font-size:16px}\n.pillars{display:flex;flex-direction:column;gap:14px;margin-top:32px}\n.pillar{display:flex;gap:14px;align-items:flex-start}\n.pillar-dot{width:32px;height:32px;flex-shrink:0;border-radius:50%;background:rgba(26,122,74,.1);border:2px solid var(--jade);display:flex;align-items:center;justify-content:center;font-size:14px;color:var(--jade);font-weight:700}\n.pillar-body{font-size:15px}\n.pillar-body strong{color:var(--ink);display:block}\n.pillar-body span{color:var(--muted);font-size:13px}\n\n/* Footer */\nfooter{background:var(--ink);padding:60px 6% 30px;color:rgba(255,255,255,.6)}\n.footer-top{display:flex;justify-content:space-between;gap:40px;flex-wrap:wrap;padding-bottom:40px;border-bottom:1px solid rgba(255,255,255,.08);margin-bottom:30px}\n.footer-brand .logo-text{color:var(--white)}\n.footer-brand p{font-size:14px;margin-top:10px;max-width:260px;font-weight:300}\n.footer-links h5{font-size:13px;font-weight:600;color:var(--white);letter-spacing:1px;text-transform:uppercase;margin-bottom:14px}\n.footer-links a{display:block;color:rgba(255,255,255,.55);text-decoration:none;font-size:14px;margin-bottom:8px;transition:color .2s}\n.footer-links a:hover{color:var(--gold)}\n.footer-bottom{display:flex;justify-content:space-between;flex-wrap:wrap;gap:10px;font-size:13px}\n.footer-bottom strong{color:var(--gold)}\n\n/* Auth gate */\n#auth-gate{position:fixed;inset:0;z-index:9998;background:var(--ink);display:flex;align-items:center;justify-content:center}\n#auth-gate .spinner{width:40px;height:40px;border:3px solid rgba(201,168,76,.2);border-top-color:var(--gold);border-radius:50%;animation:spin .8s linear infinite}\n\n@keyframes fadeUp{from{opacity:0;transform:translateY(24px)}to{opacity:1;transform:none}}\n@keyframes spin{to{transform:rotate(360deg)}}\n.tc{transition:opacity .5s ease,transform .5s ease}\n\n@media(max-width:768px){\n  nav{display:none}\n  nav.open{display:flex;flex-direction:column;position:fixed;top:70px;left:0;right:0;background:var(--ink);padding:16px;border-bottom:1px solid var(--border);z-index:800}\n  .hamburger{display:flex}\n  .hero-stats{position:static;margin-top:48px;justify-content:flex-start}\n  .hero{padding-bottom:60px}\n  .form-wrapper,.consult-form-wrap{padding:28px}\n}\n@media(max-width:480px){\n  header{padding:0 4%}\n  .section{padding:60px 4%}\n  .hero{padding:80px 4% 60px}\n  .hero-stats{flex-wrap:wrap;gap:24px}\n}\n</style>\n</head>\n<body>\n\n<div id=\"auth-gate\"><div class=\"spinner\"></div></div>\n\n<!-- HEADER -->\n<header>\n  <a href=\"#\" class=\"logo\">\n    <div class=\"logo-icon\">🛡</div>\n    <span class=\"logo-text\">Land<span>Guard</span> NG</span>\n  </a>\n  <nav id=\"main-nav\">\n    <a href=\"#checklist\">Checklist</a>\n    <a href=\"#verify\">Verify Docs</a>\n    <a href=\"#lga\">Find Registry</a>\n    <a href=\"#report\">Report</a>\n    <a href=\"#consult\">Consult</a>\n    <a href=\"#about\">About</a>\n    <div class=\"user-pill\" id=\"user-pill\" style=\"display:none\">\n      <div class=\"user-avatar\" id=\"user-avatar\">?</div>\n      <span class=\"user-name\" id=\"user-name\">User</span>\n      <button class=\"logout-btn\" onclick=\"logout()\">Sign Out</button>\n    </div>\n  </nav>\n  <div class=\"hamburger\" onclick=\"toggleMenu()\"><span></span><span></span><span></span></div>\n</header>\n\n<!-- HERO -->\n<section class=\"hero\">\n  <div class=\"hero-bg\"></div>\n  <canvas id=\"hero-canvas\"></canvas>\n  <div class=\"hero-content\">\n    <div class=\"hero-badge\">🇳🇬 &nbsp;Nigeria's Land Protection Platform</div>\n    <h1>Buy Land in Nigeria<br><em>Without the Fear</em></h1>\n    <p>Avoid fraud, verify titles, and protect your investment with expert guidance tailored for Nigerian property transactions.</p>\n    <div class=\"hero-actions\">\n      <button class=\"btn btn-gold\" onclick=\"scrollTo('checklist')\">Start Verification →</button>\n      <button class=\"btn btn-outline\" onclick=\"scrollTo('report')\">Report Suspicious Land</button>\n    </div>\n  </div>\n  <div class=\"hero-stats\">\n    <div class=\"stat\"><div class=\"stat-num\" id=\"stat-reports\">0</div><div class=\"stat-label\">Reports Filed</div></div>\n    <div class=\"stat\"><div class=\"stat-num\">12</div><div class=\"stat-label\">States Covered</div></div>\n    <div class=\"stat\"><div class=\"stat-num\">24h</div><div class=\"stat-label\">Response Time</div></div>\n  </div>\n</section>\n\n<!-- CHECKLIST -->\n<section class=\"section\" id=\"checklist\">\n  <div class=\"section-header\">\n    <div class=\"section-label\">Before You Pay</div>\n    <h2 class=\"section-title\">Land Buying Checklist</h2>\n    <p class=\"section-sub\">Complete every step before handing over any money. No exceptions.</p>\n  </div>\n  <div class=\"checklist-grid\">\n    <div class=\"check-card tc\"><div class=\"check-icon\">📜</div><div class=\"check-body\"><div class=\"check-step\">Step 01</div><div class=\"check-title\">Confirm the Land Title</div><div class=\"check-desc\">Verify the document type — C of O, Gazette, or Excision — and confirm it is valid and government-issued.</div></div></div>\n    <div class=\"check-card tc\"><div class=\"check-icon\">🏛</div><div class=\"check-body\"><div class=\"check-step\">Step 02</div><div class=\"check-title\">Search the Land Registry</div><div class=\"check-desc\">Visit the State Land Registry to confirm there are no encumbrances, disputes, or government acquisitions on the land.</div></div></div>\n    <div class=\"check-card tc\"><div class=\"check-icon\">🗺</div><div class=\"check-body\"><div class=\"check-step\">Step 03</div><div class=\"check-title\">Verify the Survey Plan</div><div class=\"check-desc\">Cross-check the survey plan coordinates with SURCON (Surveyors Council of Nigeria) to confirm the plan is legitimate.</div></div></div>\n    <div class=\"check-card tc\"><div class=\"check-icon\">👤</div><div class=\"check-body\"><div class=\"check-step\">Step 04</div><div class=\"check-title\">Confirm Rightful Ownership</div><div class=\"check-desc\">Request valid ID from the seller. Cross-reference with title documents. Be wary of multiple sellers for a single plot.</div></div></div>\n    <div class=\"check-card tc\"><div class=\"check-icon\">🔎</div><div class=\"check-body\"><div class=\"check-step\">Step 05</div><div class=\"check-title\">Physical Inspection</div><div class=\"check-desc\">Visit the land in person. Confirm boundaries match the survey plan. Talk to neighbours about any disputes.</div></div></div>\n    <div class=\"check-card tc\"><div class=\"check-icon\">⚖️</div><div class=\"check-body\"><div class=\"check-step\">Step 06</div><div class=\"check-title\">Engage a Lawyer</div><div class=\"check-desc\">All transactions should be concluded by a registered legal practitioner. Never sign without legal review.</div></div></div>\n  </div>\n</section>\n\n<!-- VERIFY DOCS -->\n<section class=\"section\" id=\"verify\" style=\"background:var(--forest)\">\n  <div class=\"section-header\">\n    <div class=\"section-label\" style=\"color:var(--gold)\">Know Your Documents</div>\n    <h2 class=\"section-title\" style=\"color:var(--white)\">Document Verification Guide</h2>\n    <p class=\"section-sub\" style=\"color:rgba(255,255,255,.6)\">Understanding these documents can save you from losing millions of naira to fraudsters.</p>\n  </div>\n  <div class=\"docs-grid\">\n    <div class=\"doc-card tc\"><div class=\"doc-tag\">Ownership Proof</div><h4>Certificate of Occupancy (C of O)</h4><p>The gold standard of Nigerian land documents. Issued by the State Governor under the Land Use Act, it confirms the holder's legal right to occupy the land for 99 years.</p></div>\n    <div class=\"doc-card tc\"><div class=\"doc-tag\">Government Record</div><h4>Gazette</h4><p>An official government publication recording excised land. It confirms the land has been officially recognised and released by the government. Always verify the date and volume number.</p></div>\n    <div class=\"doc-card tc\"><div class=\"doc-tag\">Release Approval</div><h4>Excision</h4><p>A government-approved release of land from government acquisition, typically for community or family land. Excised land is removed from the gazette and returned to original owners.</p></div>\n    <div class=\"doc-card tc\"><div class=\"doc-tag\">Technical Drawing</div><h4>Survey Plan</h4><p>A technical document prepared by a licensed surveyor showing exact land coordinates, dimensions, and boundaries. Must be stamped and signed by a registered surveyor. Verify with SURCON.</p></div>\n    <div class=\"doc-card tc\"><div class=\"doc-tag\">Family Land</div><h4>Deed of Assignment</h4><p>A legal document transferring ownership from one party to another. It must be executed by a lawyer, stamped by the Land Registry, and registered. Beware of unregistered deeds.</p></div>\n    <div class=\"doc-card tc\"><div class=\"doc-tag\">⚠️ Caution</div><h4>Red Flag Documents</h4><p>Be wary of photocopies without originals, documents with altered dates, informal receipts as primary proof, and any seller refusing a Land Registry search. Serious warning signs.</p></div>\n  </div>\n</section>\n\n<!-- LGA DIRECTORY -->\n<section class=\"section\" id=\"lga\">\n  <div class=\"section-header\">\n    <div class=\"section-label\">Find Your Registry</div>\n    <h2 class=\"section-title\">LGA Contact Directory</h2>\n    <p class=\"section-sub\">Select your state and LGA to find the exact Land Registry, SURCON office, and key contacts for where you want to buy.</p>\n  </div>\n  <div class=\"lga-bar\">\n    <select class=\"lga-select\" id=\"state-sel\" onchange=\"onState()\">\n      <option value=\"\">— Select a State —</option>\n      <option value=\"lagos\">Lagos State</option>\n      <option value=\"abuja\">FCT — Abuja</option>\n      <option value=\"rivers\">Rivers State</option>\n      <option value=\"ogun\">Ogun State</option>\n      <option value=\"oyo\">Oyo State</option>\n      <option value=\"kano\">Kano State</option>\n      <option value=\"delta\">Delta State</option>\n      <option value=\"anambra\">Anambra State</option>\n      <option value=\"enugu\">Enugu State</option>\n      <option value=\"edo\">Edo State</option>\n      <option value=\"imo\">Imo State</option>\n      <option value=\"cross_river\">Cross River State</option>\n    </select>\n    <select class=\"lga-select\" id=\"lga-sel\" onchange=\"onLga()\" disabled>\n      <option value=\"\">— Select an LGA —</option>\n    </select>\n  </div>\n  <div class=\"lga-placeholder\" id=\"lga-ph\"><div class=\"ph-icon\">🗺</div><p>Select your state and LGA above to see<br>the right contacts for your land purchase.</p></div>\n  <div class=\"lga-result\" id=\"lga-res\"><h3 id=\"lga-title\"></h3><div class=\"lga-contacts\" id=\"lga-contacts\"></div></div>\n</section>\n\n<!-- REPORT FORM -->\n<section class=\"section section-alt\" id=\"report\">\n  <div class=\"form-wrapper\">\n    <div class=\"section-label\">Community Protection</div>\n    <h3>Report Suspicious Property</h3>\n    <p class=\"sub\">Help protect others. Your report is kept confidential and reviewed by our team.</p>\n    <form id=\"report-form\">\n      <div class=\"form-row\">\n        <div class=\"field\"><label>Property Location *</label><input type=\"text\" name=\"location\" placeholder=\"e.g. Ibeju Lekki, Lagos\" required></div>\n        <div class=\"field\"><label>Agent or Company Name</label><input type=\"text\" name=\"agent\" placeholder=\"Optional\"></div>\n      </div>\n      <div class=\"form-row\">\n        <div class=\"field\"><label>Your Name</label><input type=\"text\" name=\"reporterName\" id=\"rpt-name\" placeholder=\"Auto-filled from account\"></div>\n        <div class=\"field\"><label>Your Phone</label><input type=\"tel\" name=\"phone\" id=\"rpt-phone\" placeholder=\"Auto-filled from account\"></div>\n      </div>\n      <div class=\"field\"><label>Your Email (for updates)</label><input type=\"email\" name=\"reporterEmail\" placeholder=\"Optional\"></div>\n      <div class=\"field\"><label>Describe the Issue *</label><textarea name=\"issue\" placeholder=\"Describe the suspicious activity in detail — documents shown, what was said, how you found out...\" required></textarea></div>\n      <div class=\"field\">\n        <label>Upload Evidence <span style=\"font-weight:400;color:var(--muted)\">(photo or document — max 2MB)</span></label>\n        <div class=\"upload-box\" id=\"upload-box\" onclick=\"document.getElementById('ev-input').click()\">\n          <div class=\"upload-icon\">📎</div>\n          <div class=\"upload-text\">Click to attach a photo or document</div>\n          <div class=\"upload-hint\">JPG, PNG, PDF up to 2MB</div>\n        </div>\n        <input type=\"file\" id=\"ev-input\" accept=\".jpg,.jpeg,.png,.gif,.webp,.pdf\" style=\"display:none\" onchange=\"onFileSelect(this)\">\n        <div class=\"file-preview\" id=\"file-preview\">\n          <span id=\"file-icon\" style=\"font-size:22px\">📄</span>\n          <div style=\"flex:1\"><div id=\"file-name\" style=\"font-size:13px;font-weight:600;color:var(--ink)\"></div><div id=\"file-size\" style=\"font-size:12px;color:var(--muted)\"></div></div>\n          <button type=\"button\" onclick=\"removeFile()\" style=\"background:none;border:none;cursor:pointer;color:#ef4444;font-size:18px;padding:4px\">✕</button>\n        </div>\n      </div>\n      <button type=\"submit\" class=\"submit-btn\" id=\"report-btn\"><span>Submit Report</span><span>🔒</span></button>\n    </form>\n    <p style=\"font-size:13px;color:var(--muted);margin-top:16px;text-align:center\">All reports are reviewed within 48 hours and treated confidentially.</p>\n  </div>\n</section>\n\n<!-- CTA -->\n<div class=\"cta-strip\">\n  <div><h2>Need Expert Guidance?</h2><p>Book a free consultation with our property verification specialists.</p></div>\n  <button class=\"btn btn-gold\" onclick=\"scrollTo('consult')\">Book Free Consultation →</button>\n</div>\n\n<!-- CONSULTATION -->\n<section class=\"section\" id=\"consult\">\n  <div class=\"consult-form-wrap\">\n    <div class=\"section-label\">Expert Advice</div>\n    <h3 style=\"font-family:var(--fh);font-size:28px;color:var(--ink);margin-bottom:8px\">Book a Consultation</h3>\n    <p style=\"color:var(--muted);margin-bottom:36px;font-size:15px;font-weight:300\">Fill in your details and we'll reach out within 24 hours.</p>\n    <form id=\"consult-form\">\n      <div class=\"form-row\">\n        <div class=\"field\"><label>Full Name *</label><input type=\"text\" name=\"name\" placeholder=\"Your full name\" required></div>\n        <div class=\"field\"><label>Email Address *</label><input type=\"email\" name=\"email\" placeholder=\"your@email.com\" required></div>\n      </div>\n      <div class=\"form-row\">\n        <div class=\"field\"><label>Phone Number</label><input type=\"tel\" name=\"phone\" placeholder=\"+234 000 000 0000\"></div>\n        <div class=\"field\"><label>Service Needed</label>\n          <select name=\"service\">\n            <option>Document Verification</option>\n            <option>Land Registry Search</option>\n            <option>Survey Plan Check</option>\n            <option>Legal Referral</option>\n            <option>General Inquiry</option>\n          </select>\n        </div>\n      </div>\n      <div class=\"field\"><label>Additional Information</label><textarea name=\"message\" placeholder=\"Tell us more about your situation...\" rows=\"4\"></textarea></div>\n      <button type=\"submit\" class=\"submit-btn\" id=\"consult-btn\"><span>Request Consultation</span><span>📅</span></button>\n    </form>\n  </div>\n</section>\n\n<!-- ABOUT -->\n<section class=\"section section-alt\" id=\"about\">\n  <div class=\"about-grid\">\n    <div class=\"about-visual\">\n      <div class=\"big-num\">36+</div>\n      <p>States covered across Nigeria's land registry network</p>\n      <div style=\"margin-top:28px;display:flex;gap:24px\">\n        <div style=\"text-align:center\"><div style=\"font-family:var(--fh);font-size:28px;color:var(--gold)\">98%</div><div style=\"font-size:12px;color:rgba(255,255,255,.5);margin-top:4px\">Fraud Prevented</div></div>\n        <div style=\"text-align:center\"><div style=\"font-family:var(--fh);font-size:28px;color:var(--gold)\">₦∞</div><div style=\"font-size:12px;color:rgba(255,255,255,.5);margin-top:4px\">Losses Avoided</div></div>\n      </div>\n    </div>\n    <div class=\"about-text\">\n      <div class=\"section-label\">Our Mission</div>\n      <h2 class=\"section-title\">Protecting Property Buyers Across Nigeria</h2>\n      <p>LandGuard NG was created in response to Nigeria's rising land fraud epidemic. We equip buyers with the knowledge, tools, and connections to make safe, informed property decisions.</p>\n      <p>Whether you're buying family land in Ogun State, commercial plots in Lagos, or residential land in Abuja — we provide the framework to protect your investment.</p>\n      <div class=\"pillars\">\n        <div class=\"pillar\"><div class=\"pillar-dot\">1</div><div class=\"pillar-body\"><strong>Education First</strong><span>We teach buyers exactly what to look for and what to avoid in every transaction.</span></div></div>\n        <div class=\"pillar\"><div class=\"pillar-dot\">2</div><div class=\"pillar-body\"><strong>Community Reporting</strong><span>Our report system flags known fraudsters and suspicious properties to protect the community.</span></div></div>\n        <div class=\"pillar\"><div class=\"pillar-dot\">3</div><div class=\"pillar-body\"><strong>Expert Network</strong><span>We connect buyers with trusted surveyors, lawyers, and registry officials.</span></div></div>\n      </div>\n      <p style=\"margin-top:28px;font-size:14px;color:var(--muted)\">Powered by <strong style=\"color:var(--ink)\">DavidskilTech</strong></p>\n    </div>\n  </div>\n</section>\n\n<!-- FOOTER -->\n<footer>\n  <div class=\"footer-top\">\n    <div class=\"footer-brand\">\n      <div class=\"logo\"><div class=\"logo-icon\">🛡</div><span class=\"logo-text\">Land<span>Guard</span> NG</span></div>\n      <p>Nigeria's trusted land transaction safety platform.</p>\n    </div>\n    <div class=\"footer-links\"><h5>Platform</h5><a href=\"#checklist\">Buying Checklist</a><a href=\"#verify\">Document Guide</a><a href=\"#lga\">Find Registry</a><a href=\"#report\">Report Fraud</a><a href=\"#consult\">Consultation</a></div>\n    <div class=\"footer-links\"><h5>Resources</h5><a href=\"#about\">About LandGuard</a><a href=\"#verify\">C of O Explained</a><a href=\"#verify\">Survey Plan Guide</a><a href=\"#report\">Contact Us</a></div>\n  </div>\n  <div class=\"footer-bottom\">\n    <span>© 2026 LandGuard NG — Protecting Property Buyers Across Nigeria</span>\n    <span>Powered by <strong>DavidskilTech</strong></span>\n  </div>\n</footer>\n<div id=\"toast\"></div>\n\n<script>\n// ── LGA DATA ──────────────────────────────────────────────────\nconst LGA={\n  lagos:{name:'Lagos State',registry:{name:'Lagos State Land Registry (HQ)',address:'The Secretariat, Alausa, Ikeja, Lagos',phone:'01-740-7000',email:'info@lagoslands.gov.ng',hours:'Mon–Fri, 8am–4pm'},surcon:{name:'SURCON Lagos Regional Office',address:'Ikoyi, Lagos Island',phone:'01-269-5671'},caution:'Confirm land is not in a government acquisition zone — especially in Lekki, Ibeju-Lekki, and Epe corridors.',lgas:{'Alimosho':{zone:'Alimosho Land Registry Sub-Office, Akowonjo',phone:'01-774-0000',note:'Fastest growing LGA. High fraud risk — always demand original C of O.'},'Epe':{zone:'Epe Land Registry, Epe Town Centre',phone:'01-980-7500',note:'Booming corridor — many forest reserves and acquired lands. Verify excision carefully.'},'Eti-Osa':{zone:'Lekki Land Registry, Lekki Phase 1',phone:'01-271-0000',note:'Lekki Phase 1 & 2 — beware reclaimed land without C of O. Oceanfront land frequently disputed.'},'Ibeju-Lekki':{zone:'Ibeju-Lekki Land Registry, Epe Expressway',phone:'01-980-8000',note:'⚠️ HIGHEST FRAUD RISK in Lagos. Most land has no C of O. Demand excision and verify at Alausa HQ.'},'Ikeja':{zone:'Ikeja Land Registry, Oba Akinjobi Road GRA',phone:'01-496-8000',note:'GRA Ikeja properties require LEDB clearance.'},'Ikorodu':{zone:'Ikorodu Land Registry, Ikorodu Town Hall',phone:'01-689-5000',note:'Industrial expansion zone. Many recent excisions — verify dates carefully.'},'Lagos Island':{zone:'Lagos Island Land Registry, Tinubu Square',phone:'01-263-5000',note:'Historic Crown Land — consult a lawyer experienced in Lagos Island tenure.'},'Mushin':{zone:'Mushin Land Office, Mushin Road',phone:'01-452-6000',note:'Dense urban area — boundary disputes common. Commission an independent survey.'},'Surulere':{zone:'Surulere Land Registry, Adeniran Ogunsanya St',phone:'01-774-8800',note:'Relatively well-documented. Verify for any LSDPC encumbrances.'},'Badagry':{zone:'Badagry Land Registry, Badagry Expressway',phone:'01-773-4000',note:'Border town — verify nationality status of land and seller ID carefully.'},'Agege':{zone:'Agege Land Registry Sub-Office, Agege Town Hall',phone:'01-496-1000',note:'Many family lands — ensure excision is complete before purchase.'},'Apapa':{zone:'Apapa Land Registry, Apapa Wharf Road',phone:'01-545-0700',note:'Port industrial zone. Most land held under Federal Government titles.'}}},\n  abuja:{name:'FCT — Abuja',registry:{name:'Abuja Geographic Information Systems (AGIS)',address:'Plot 508 Zone AO, Central Business District, Abuja',phone:'09-461-3360',email:'info@agis.gov.ng',hours:'Mon–Fri, 8am–4pm'},surcon:{name:'SURCON FCT Office',address:'Garki Area 1, Abuja',phone:'09-234-5678'},caution:'All land in Abuja belongs to the Federal Government. You can only acquire a Right of Occupancy (R of O). Beware of anyone selling \"family land\" in the FCT — it does not legally exist.',lgas:{'Abuja Municipal (AMAC)':{zone:'AGIS Main Office, Central Business District',phone:'09-461-3360',note:'Core Abuja. All transactions must go through AGIS.'},'Bwari':{zone:'Bwari Area Council Registry, Bwari Township',phone:'09-461-3200',note:'Rapid development area. Verify FCDA layout approval.'},'Gwagwalada':{zone:'Gwagwalada Area Council Land Office',phone:'09-461-3400',note:'University town — lots of fraudulent allocations near UniAbuja.'},'Kuje':{zone:'Kuje Area Council Land Registry',phone:'09-461-3500',note:'Agricultural/peri-urban zone. Verify Federal Government acquisition status.'},'Abaji':{zone:'Abaji Area Council Land Registry',phone:'09-461-3000',note:'Peri-urban area — ensure plot falls within approved layout.'}}},\n  rivers:{name:'Rivers State',registry:{name:'Rivers State Ministry of Lands',address:'State Secretariat Complex, Moscow Road, Port Harcourt',phone:'084-239-000',email:'lands@rivers.gov.ng',hours:'Mon–Fri, 8am–4pm'},surcon:{name:'SURCON South-South Regional Office',address:'Trans-Amadi Industrial Layout, Port Harcourt',phone:'084-236-000'},caution:'Oil company pipeline corridors and community land disputes are common. Always verify community consent and check for oil company right-of-way encumbrances.',lgas:{'Port Harcourt':{zone:'Port Harcourt Land Registry, Moscow Road',phone:'084-230-000',note:'Capital city — best documentation. GRA PH requires PHDCL clearance.'},'Obio-Akpor':{zone:'Rumuola Land Office, Obio-Akpor',phone:'084-231-500',note:'Fastest growing area. High fraud risk around Rumuola and Rumuigbo corridors.'},'Eleme':{zone:'Eleme Land Registry, Eleme Junction',phone:'084-412-000',note:'Heavy oil industry — verify no NLNG or SPDC pipeline crossings.'},'Ikwerre':{zone:'Isiokpo Land Office, Ikwerre LGA',phone:'084-320-000',note:'Family land dominates — community consent letters from village heads are essential.'}}},\n  ogun:{name:'Ogun State',registry:{name:'Ogun State Land Registry (OLAS)',address:'Oke-Mosan Secretariat, Abeokuta',phone:'039-241-000',email:'info@ogunlands.gov.ng',hours:'Mon–Fri, 8am–4pm'},surcon:{name:'SURCON South-West Regional Office',address:'Ibadan Road, Abeokuta',phone:'039-240-500'},caution:'Ogun is the biggest source of Lagos overspill land purchases. The Sagamu-Ore and Lagos-Abeokuta corridors have very high rates of multiple-selling fraud. Always verify at OLAS.',lgas:{'Sagamu':{zone:'Sagamu Land Registry, Lagos Road, Sagamu',phone:'037-640-000',note:'⚠️ HIGH FRAUD RISK. Proximity to Lagos drives intense land speculation. Demand original C of O.'},'Ifo':{zone:'Ifo Land Office, Lagos-Abeokuta Expressway',phone:'039-271-000',note:'Sango-Ota corridor — many informal layouts. Verify with OLAS.'},'Abeokuta South':{zone:'Abeokuta Land Registry, Oke-Mosan',phone:'039-241-100',note:'State capital. Well-documented. Check development restrictions around Olumo Rock.'},'Ijebu Ode':{zone:'Ijebu Ode Land Registry, Folagbade Street',phone:'037-432-000',note:'Strong land documentation culture. Ijebu family land sales without consent are common.'}}},\n  oyo:{name:'Oyo State',registry:{name:'Oyo State Land Registry',address:'State Secretariat, Agodi, Ibadan',phone:'02-241-6000',email:'lands@oyostate.gov.ng',hours:'Mon–Fri, 8am–4pm'},surcon:{name:'SURCON South-West Regional Office',address:'Iyaganku GRA, Ibadan',phone:'02-241-0500'},caution:'Ibadan has a complex mix of Crown Land, government layouts, and family land (Ibile). Multiple sales of the same plot by different family factions are common. Legal advice is essential.',lgas:{'Ibadan North':{zone:'Sasa Land Registry, Ring Road, Ibadan',phone:'02-241-7000',note:'University of Ibadan proximity — UI land acquisition buffer must be checked.'},'Ibadan South-West':{zone:'Bodija Land Office, Bodija, Ibadan',phone:'02-241-8000',note:'Bodija Estate — BDPA allocation required. Check for pending BDPA charges.'},'Oluyole':{zone:'New Bodija Land Office, Oluyole Estate',phone:'02-290-5000',note:'Active development zone with strong documentation.'},'Ogbomoso North':{zone:'Ogbomoso Land Registry, Ogbomoso Town Centre',phone:'038-720-000',note:'Secondary city. Check Lautech institution acquisitions.'}}},\n  kano:{name:'Kano State',registry:{name:'Kano State Ministry of Lands & Physical Planning',address:'Bompai Road, Kano Municipal',phone:'064-646-000',email:'lands@kanostate.gov.ng',hours:'Mon–Fri, 8am–4pm'},surcon:{name:'SURCON North Regional Office',address:'Nassarawa GRA, Kano',phone:'064-630-000'},caution:'Kano operates under dual land tenure — statutory (government title) and customary (emirate/community). Ensure any purchase has a formal statutory title, not just customary rights.',lgas:{'Kano Municipal':{zone:'Kano Municipal Land Registry, Bompai Road',phone:'064-646-100',note:'State capital. Best documentation. Verify heritage zone restrictions near the Old City.'},'Nassarawa':{zone:'Nassarawa GRA Land Office, Kano',phone:'064-646-300',note:'GRA area — well-documented. Still verify for dual allocations.'},'Gwale':{zone:'Gwale Land Registry, Gwale',phone:'064-646-500',note:'Traditional core area — customary rights dominant. Expert legal advice essential.'}}},\n  delta:{name:'Delta State',registry:{name:'Delta State Ministry of Lands, Survey & Urban Planning',address:'Government House Road, Asaba',phone:'046-282-000',email:'lands@deltastate.gov.ng',hours:'Mon–Fri, 8am–4pm'},surcon:{name:'SURCON South-South Regional Office',address:'Effurun, Warri',phone:'053-250-000'},caution:'Oil community land in Delta is highly contentious. Verify the community has legal authority to sell and that no pending oil spillage compensation claims exist.',lgas:{'Warri South':{zone:'Warri Land Registry, Effurun Road, Warri',phone:'053-253-000',note:'Oil city — high land values and fraud risk. Verify with Ministry HQ in Asaba.'},'Oshimili South':{zone:'Asaba Land Registry, Nnebisi Road, Asaba',phone:'046-283-000',note:'Capital city area. Best documentation in the state.'},'Sapele':{zone:'Sapele Land Registry, Sapele Town',phone:'054-430-000',note:'Timber and rubber belt — check agricultural/forest reserve acquisition zones.'}}},\n  anambra:{name:'Anambra State',registry:{name:'Anambra State Ministry of Lands',address:'Udoka Housing Estate, Awka',phone:'048-550-000',email:'lands@anambra.gov.ng',hours:'Mon–Fri, 8am–4pm'},surcon:{name:'SURCON South-East Regional Office',address:'Onitsha Road, Awka',phone:'048-551-000'},caution:'Family land (Ala Ulo) sales without full family consent are the most common fraud vector in Anambra. Always demand a family resolution letter signed by all principal members.',lgas:{'Onitsha North':{zone:'Onitsha Land Registry, New Market Road',phone:'046-212-000',note:'Commercial hub — highest land demand. Multiple-selling is rampant. Lawyer is mandatory.'},'Awka South':{zone:'Awka Land Registry, Udoka Avenue, Awka',phone:'048-552-000',note:'State capital. Government layouts well-documented. Still verify family land sales.'},'Nnewi North':{zone:'Nnewi Land Registry, Nnewi Town Centre',phone:'046-460-000',note:'Industrial/auto parts city. Verify Nnewi customary land boundaries carefully.'}}},\n  enugu:{name:'Enugu State',registry:{name:'Enugu State Ministry of Lands, Survey & Urban Dev.',address:'Independence Layout, Enugu',phone:'042-455-000',email:'lands@enugu.gov.ng',hours:'Mon–Fri, 8am–4pm'},surcon:{name:'SURCON South-East Regional Office',address:'GRA Enugu',phone:'042-456-000'},caution:'Coal mining legacy means parts of Enugu have underground mine workings. Do NOT buy land near old Enugu Coal mines without geological clearance from NIOMCO.',lgas:{'Enugu North':{zone:'Enugu North Land Registry, Independence Layout',phone:'042-455-100',note:'GRA and Independence Layout — best documented. Verify for coal mine buffer zones.'},'Enugu South':{zone:'Enugu South Land Office, Uwani',phone:'042-455-200',note:'Uwani residential area — active market. Standard due diligence applies.'},'Udi':{zone:'Udi Land Registry, Udi Town',phone:'042-810-000',note:'Coal belt — geological clearance essential before any purchase.'}}},\n  edo:{name:'Edo State',registry:{name:'Edo State Ministry of Lands & Survey',address:'Government House Road, Benin City',phone:'052-256-000',email:'lands@edostate.gov.ng',hours:'Mon–Fri, 8am–4pm'},surcon:{name:'SURCON South-South Regional Office',address:'GRA Benin City',phone:'052-258-000'},caution:\"Benin City plots in the Oba of Benin's original jurisdiction require traditional consent (Oba's approval) IN ADDITION to government documentation. Do not skip this step.\",lgas:{'Oredo':{zone:'Oredo Land Registry, Ring Road, Benin City',phone:'052-257-000',note:\"Benin City core — both government C of O AND Oba's consent may be required.\"},'Egor':{zone:'Egor Land Office, Ugbowo, Benin City',phone:'052-259-000',note:'UNIBEN proximity — university acquisition buffer zone check required.'},'Ovia North-East':{zone:'Ovia Land Registry, Ore Road, Ovia',phone:'052-270-000',note:'Rubber plantation belt — verify no forestry/agriculture reserve encumbrances.'}}},\n  imo:{name:'Imo State',registry:{name:'Imo State Ministry of Lands, Survey & Urban Planning',address:'Douglas Road, Owerri',phone:'083-231-000',email:'lands@imostate.gov.ng',hours:'Mon–Fri, 8am–4pm'},surcon:{name:'SURCON South-East Regional Office',address:'New Owerri',phone:'083-232-000'},caution:\"Family land (Obi) sales without all sons' consent is the leading cause of fraud in Imo. Always demand a family meeting resolution letter. Owerri North/Municipal boundary disputes are common.\",lgas:{'Owerri Municipal':{zone:'Owerri Municipal Land Registry, Douglas Road',phone:'083-231-100',note:'State capital area. Best documentation. Verify boundary with Owerri North.'},'Owerri North':{zone:'Owerri North Land Office, Irete',phone:'083-231-200',note:'Peri-urban expansion zone. High fraud activity — verify at HQ.'},'Orlu':{zone:'Orlu Land Registry, Orlu Town Centre',phone:'083-440-000',note:'Orlu zone — family land dominant. Consent from Umunna (extended family) required.'}}},\n  cross_river:{name:'Cross River State',registry:{name:'Cross River State Ministry of Lands & Housing',address:'Mary Slessor Avenue, Calabar',phone:'087-232-000',email:'lands@crossriverstate.gov.ng',hours:'Mon–Fri, 8am–4pm'},surcon:{name:'SURCON South-South Regional Office',address:'Calabar Road, Calabar',phone:'087-233-000'},caution:'Some areas around Creek Town and the colonial waterfront are UNESCO heritage zones with development restrictions. Verify with the Cross River State Tourism Commission.',lgas:{'Calabar Municipal':{zone:'Calabar Municipal Land Registry, MCC Road',phone:'087-234-000',note:'Capital city. Heritage zone maps available at the Ministry. Consular areas need special clearances.'},'Calabar South':{zone:'Calabar South Land Office, Marian Road',phone:'087-235-000',note:'Port area — waterfront land requires Cross River Basin Development Authority clearance.'},'Odukpani':{zone:'Odukpani Land Office, Odukpani',phone:'087-236-000',note:'Rubber and palm plantation belt. Verify no CRSFDA agricultural reserve encumbrances.'}}}\n};\n\nfunction onState(){\n  const sk=document.getElementById('state-sel').value, ls=document.getElementById('lga-sel');\n  ls.innerHTML='<option value=\"\">— Select an LGA —</option>'; ls.disabled=true;\n  document.getElementById('lga-res').classList.remove('show');\n  document.getElementById('lga-ph').style.display='block';\n  if(!sk||!LGA[sk])return;\n  Object.keys(LGA[sk].lgas).sort().forEach(n=>{const o=document.createElement('option');o.value=n;o.textContent=n;ls.appendChild(o);});\n  ls.disabled=false;\n}\nfunction onLga(){\n  const sk=document.getElementById('state-sel').value, lk=document.getElementById('lga-sel').value;\n  if(!sk||!lk)return;\n  const st=LGA[sk], lg=st.lgas[lk]; if(!lg)return;\n  document.getElementById('lga-ph').style.display='none';\n  document.getElementById('lga-title').textContent=lk+' — '+st.name;\n  document.getElementById('lga-contacts').innerHTML=[\n    {type:'🏛 Land Registry HQ',name:st.registry.name,detail:`<b>Address:</b> ${st.registry.address}<br><b>Phone:</b> <a href=\"tel:${st.registry.phone}\">${st.registry.phone}</a><br><b>Hours:</b> ${st.registry.hours}${st.registry.email?`<br><b>Email:</b> <a href=\"mailto:${st.registry.email}\">${st.registry.email}</a>`:''}`},\n    {type:'📍 Local Zone Office',name:lg.zone,detail:`<b>Phone:</b> <a href=\"tel:${lg.phone}\">${lg.phone}</a>`},\n    {type:'📐 SURCON Regional Office',name:st.surcon.name,detail:`<b>Address:</b> ${st.surcon.address}<br><b>Phone:</b> <a href=\"tel:${st.surcon.phone}\">${st.surcon.phone}</a>`},\n    {type:'⚠️ Key Note for this LGA',name:'',detail:lg.note},\n    {type:'🚨 State-Wide Caution',name:'',detail:st.caution}\n  ].map(c=>`<div class=\"contact-card\"><div class=\"contact-type\">${c.type}</div>${c.name?`<div class=\"contact-name\">${c.name}</div>`:''}<div class=\"contact-detail\">${c.detail}</div></div>`).join('');\n  document.getElementById('lga-res').classList.add('show');\n  document.getElementById('lga-res').scrollIntoView({behavior:'smooth',block:'nearest'});\n}\n\n// ── File Upload ───────────────────────────────────────────────\nlet evData=null, evName=null;\nfunction onFileSelect(inp){\n  const f=inp.files[0]; if(!f)return;\n  if(f.size>2*1024*1024){showToast('⚠️ File too large. Max 2MB.','error');inp.value='';return;}\n  const r=new FileReader();\n  r.onload=e=>{\n    evData=e.target.result; evName=f.name;\n    document.getElementById('file-icon').textContent=f.type.startsWith('image/')?'🖼':'📄';\n    document.getElementById('file-name').textContent=f.name;\n    document.getElementById('file-size').textContent=(f.size/1024).toFixed(1)+' KB';\n    document.getElementById('file-preview').classList.add('show');\n    document.getElementById('upload-box').classList.add('has-file');\n    document.querySelector('.upload-text').textContent='✅ File attached';\n  };\n  r.readAsDataURL(f);\n}\nfunction removeFile(){\n  evData=null;evName=null;\n  document.getElementById('ev-input').value='';\n  document.getElementById('file-preview').classList.remove('show');\n  document.getElementById('upload-box').classList.remove('has-file');\n  document.querySelector('.upload-text').textContent='Click to attach a photo or document';\n}\n\n// ── Auth & Init ───────────────────────────────────────────────\nconst token=localStorage.getItem('lg_token');\n(async()=>{\n  if(!token){window.location.href='/login';return;}\n  try{\n    const r=await fetch('/api/auth/me',{headers:{'Authorization':'Bearer '+token}});\n    if(!r.ok){localStorage.clear();window.location.href='/login';return;}\n    const u=await r.json();\n    document.getElementById('auth-gate').style.display='none';\n    const init=(u.fullName||u.username).split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase();\n    document.getElementById('user-avatar').textContent=init;\n    document.getElementById('user-name').textContent=u.fullName||u.username;\n    document.getElementById('user-pill').style.display='flex';\n    const rn=document.getElementById('rpt-name'); if(rn)rn.value=u.fullName||u.username;\n    const rp=document.getElementById('rpt-phone'); if(rp&&u.phone)rp.value=u.phone;\n    loadStats();\n  }catch{window.location.href='/login';}\n})();\n\nasync function logout(){\n  try{await fetch('/api/auth/logout',{method:'POST',headers:{'Authorization':'Bearer '+token}});}catch{}\n  localStorage.clear(); window.location.href='/login';\n}\nfunction scrollTo(id){document.getElementById(id)?.scrollIntoView({behavior:'smooth'});}\nfunction toggleMenu(){document.getElementById('main-nav').classList.toggle('open');}\nfunction showToast(msg,type='success'){const t=document.getElementById('toast');t.textContent=msg;t.className=type+' show';setTimeout(()=>t.className=type,3500);}\nconst io=new IntersectionObserver(e=>e.forEach(x=>{if(x.isIntersecting)x.target.classList.add('visible');}),{threshold:.12});\ndocument.querySelectorAll('.tc').forEach(c=>io.observe(c));\nasync function loadStats(){\n  try{const r=await fetch('/api/stats',{headers:{'Authorization':'Bearer '+token}});if(!r.ok)return;const d=await r.json();animNum('stat-reports',d.totalReports);}catch{}\n}\nfunction animNum(id,target){\n  const el=document.getElementById(id);if(!el||!target)return;\n  let c=0;const s=Math.max(1,Math.floor(target/40));\n  const t=setInterval(()=>{c=Math.min(c+s,target);el.textContent=c;if(c>=target)clearInterval(t);},30);\n}\n\ndocument.getElementById('report-form').addEventListener('submit',async e=>{\n  e.preventDefault();\n  const btn=document.getElementById('report-btn');btn.disabled=true;btn.innerHTML='<span>Submitting...</span>';\n  const data=Object.fromEntries(new FormData(e.target).entries());\n  if(evData){data.evidenceBase64=evData;data.evidenceName=evName;}\n  try{\n    const r=await fetch('/api/report',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify(data)});\n    const j=await r.json();\n    if(r.ok){showToast('✅ Report submitted! ID: '+j.reportId);e.target.reset();removeFile();}\n    else showToast('⚠️ '+(j.error||'Submission failed'),'error');\n  }catch{showToast('⚠️ Network error — please try again','error');}\n  finally{btn.disabled=false;btn.innerHTML='<span>Submit Report</span><span>🔒</span>';}\n});\n\n// ── Hero Canvas Animation ─────────────────────────────────────\n(function(){\n  const canvas = document.getElementById('hero-canvas');\n  if (!canvas) return;\n  const ctx = canvas.getContext('2d');\n  let W, H, particles = [], buildings = [], people = [];\n\n  function resize() {\n    W = canvas.width  = canvas.offsetWidth;\n    H = canvas.height = canvas.offsetHeight;\n  }\n\n  // Survey grid dots (land plots)\n  function initParticles() {\n    particles = [];\n    const cols = Math.floor(W / 60), rows = Math.floor(H / 60);\n    for (let i = 0; i < cols; i++) {\n      for (let j = 0; j < rows; j++) {\n        if (Math.random() > 0.55) continue;\n        particles.push({\n          x: i * 60 + 30 + (Math.random()-0.5)*20,\n          y: j * 60 + 30 + (Math.random()-0.5)*20,\n          r: Math.random()*2+1,\n          alpha: Math.random()*0.6+0.1,\n          pulse: Math.random()*Math.PI*2,\n          speed: Math.random()*0.02+0.005\n        });\n      }\n    }\n  }\n\n  // Animated building silhouettes\n  function initBuildings() {\n    buildings = [];\n    const count = Math.floor(W / 80);\n    for (let i = 0; i < count; i++) {\n      const bW = 30 + Math.random()*40;\n      buildings.push({\n        x: (W / count) * i + Math.random()*20,\n        bW,\n        bH: 60 + Math.random()*120,\n        windows: Math.floor(Math.random()*6)+2\n      });\n    }\n  }\n\n  // Walking people (simple stick figures moving across)\n  function initPeople() {\n    people = [];\n    for (let i = 0; i < 8; i++) {\n      people.push({\n        x: Math.random()*W,\n        y: H * (0.72 + Math.random()*0.15),\n        speed: 0.4 + Math.random()*0.6,\n        dir: Math.random()>0.5?1:-1,\n        step: Math.random()*Math.PI*2,\n        size: 8 + Math.random()*5,\n        alpha: 0.4 + Math.random()*0.4\n      });\n    }\n  }\n\n  function drawBuildings() {\n    const baseY = H * 0.78;\n    buildings.forEach(b => {\n      // Building body\n      ctx.fillStyle = 'rgba(20,92,56,0.35)';\n      ctx.fillRect(b.x, baseY - b.bH, b.bW, b.bH);\n      // Windows\n      const wCols = 2, wRows = b.windows;\n      const wW = (b.bW - 12) / wCols - 3;\n      const wH = (b.bH - 20) / wRows - 4;\n      for (let c = 0; c < wCols; c++) {\n        for (let r = 0; r < wRows; r++) {\n          const lit = Math.random() > 0.3;\n          ctx.fillStyle = lit ? 'rgba(201,168,76,0.7)' : 'rgba(201,168,76,0.15)';\n          ctx.fillRect(b.x + 6 + c*(wW+3), baseY - b.bH + 10 + r*(wH+4), wW, wH);\n        }\n      }\n    });\n    // Ground line\n    ctx.strokeStyle = 'rgba(26,122,74,0.4)';\n    ctx.lineWidth = 1.5;\n    ctx.beginPath(); ctx.moveTo(0, baseY); ctx.lineTo(W, baseY); ctx.stroke();\n  }\n\n  function drawPerson(p) {\n    const x = p.x, y = p.y, sz = p.size;\n    ctx.save();\n    ctx.globalAlpha = p.alpha;\n    ctx.strokeStyle = '#c9a84c';\n    ctx.lineWidth = 1.5;\n    ctx.lineCap = 'round';\n    // Head\n    ctx.beginPath(); ctx.arc(x, y - sz*1.8, sz*0.5, 0, Math.PI*2); ctx.stroke();\n    // Body\n    ctx.beginPath(); ctx.moveTo(x, y-sz*1.3); ctx.lineTo(x, y-sz*0.3); ctx.stroke();\n    // Walking legs\n    const legSwing = Math.sin(p.step) * 0.4;\n    ctx.beginPath(); ctx.moveTo(x, y-sz*0.3); ctx.lineTo(x + Math.sin(legSwing)*sz*0.7, y); ctx.stroke();\n    ctx.beginPath(); ctx.moveTo(x, y-sz*0.3); ctx.lineTo(x - Math.sin(legSwing)*sz*0.7, y); ctx.stroke();\n    // Arms\n    ctx.beginPath(); ctx.moveTo(x, y-sz*1.1); ctx.lineTo(x + Math.sin(-legSwing)*sz*0.6, y-sz*0.6); ctx.stroke();\n    ctx.beginPath(); ctx.moveTo(x, y-sz*1.1); ctx.lineTo(x - Math.sin(-legSwing)*sz*0.6, y-sz*0.6); ctx.stroke();\n    ctx.restore();\n  }\n\n  // Floating land plot rectangles\n  const plots = [];\n  function initPlots() {\n    for (let i = 0; i < 12; i++) {\n      plots.push({\n        x: Math.random()*W, y: Math.random()*H*0.7,\n        w: 40+Math.random()*60, h: 30+Math.random()*40,\n        alpha: 0, targetAlpha: Math.random()*0.25+0.05,\n        fadeSpeed: 0.003+Math.random()*0.005,\n        fadeIn: true\n      });\n    }\n  }\n\n  function drawPlots() {\n    plots.forEach(p => {\n      if (p.fadeIn) { p.alpha += p.fadeSpeed; if(p.alpha >= p.targetAlpha){p.alpha=p.targetAlpha;p.fadeIn=false;} }\n      else { p.alpha -= p.fadeSpeed*0.5; if(p.alpha <= 0){p.alpha=0;p.targetAlpha=Math.random()*0.25+0.05;p.fadeIn=true;p.x=Math.random()*W;p.y=Math.random()*H*0.7;} }\n      ctx.save();\n      ctx.globalAlpha = p.alpha;\n      ctx.strokeStyle = '#c9a84c';\n      ctx.lineWidth = 1;\n      ctx.strokeRect(p.x, p.y, p.w, p.h);\n      // Plot label dot\n      ctx.fillStyle = '#22c55e';\n      ctx.beginPath(); ctx.arc(p.x+p.w/2, p.y+p.h/2, 2, 0, Math.PI*2); ctx.fill();\n      ctx.restore();\n    });\n  }\n\n  function draw(ts) {\n    ctx.clearRect(0, 0, W, H);\n\n    // Survey grid lines\n    ctx.strokeStyle = 'rgba(26,122,74,0.12)';\n    ctx.lineWidth = 0.5;\n    for (let x = 0; x < W; x += 60) { ctx.beginPath(); ctx.moveTo(x,0); ctx.lineTo(x,H); ctx.stroke(); }\n    for (let y = 0; y < H; y += 60) { ctx.beginPath(); ctx.moveTo(0,y); ctx.lineTo(W,y); ctx.stroke(); }\n\n    // Survey dots\n    particles.forEach(p => {\n      p.pulse += p.speed;\n      const a = (Math.sin(p.pulse)*0.3 + 0.7) * p.alpha;\n      ctx.beginPath();\n      ctx.arc(p.x, p.y, p.r, 0, Math.PI*2);\n      ctx.fillStyle = `rgba(201,168,76,${a})`;\n      ctx.fill();\n    });\n\n    // Connection lines between nearby dots\n    for (let i = 0; i < particles.length; i++) {\n      for (let j = i+1; j < particles.length; j++) {\n        const dx = particles[i].x - particles[j].x;\n        const dy = particles[i].y - particles[j].y;\n        const dist = Math.sqrt(dx*dx+dy*dy);\n        if (dist < 90) {\n          ctx.beginPath();\n          ctx.moveTo(particles[i].x, particles[i].y);\n          ctx.lineTo(particles[j].x, particles[j].y);\n          ctx.strokeStyle = `rgba(201,168,76,${0.08*(1-dist/90)})`;\n          ctx.lineWidth = 0.5;\n          ctx.stroke();\n        }\n      }\n    }\n\n    // Floating land plots\n    drawPlots();\n\n    // Buildings silhouette\n    drawBuildings();\n\n    // Walking people\n    people.forEach(p => {\n      p.step += 0.08;\n      p.x += p.speed * p.dir;\n      if (p.x > W + 30)  p.x = -30;\n      if (p.x < -30)     p.x = W + 30;\n      drawPerson(p);\n    });\n\n    requestAnimationFrame(draw);\n  }\n\n  function init() {\n    resize();\n    initParticles();\n    initBuildings();\n    initPeople();\n    initPlots();\n    requestAnimationFrame(draw);\n  }\n\n  window.addEventListener('resize', () => { resize(); initParticles(); initBuildings(); initPlots(); });\n  init();\n})();\n\ndocument.getElementById('consult-form').addEventListener('submit',async e=>{\n  e.preventDefault();\n  const btn=document.getElementById('consult-btn');btn.disabled=true;btn.innerHTML='<span>Sending...</span>';\n  const data=Object.fromEntries(new FormData(e.target).entries());\n  try{\n    const r=await fetch('/api/consult',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify(data)});\n    const j=await r.json();\n    if(r.ok){showToast('🎉 '+j.message);e.target.reset();}\n    else showToast('⚠️ '+(j.error||'Submission failed'),'error');\n  }catch{showToast('⚠️ Network error — please try again','error');}\n  finally{btn.disabled=false;btn.innerHTML='<span>Request Consultation</span><span>📅</span>';}\n});\n</script>\n</body>\n</html>\n",
  "login.html": "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>LandGuard NG — Login</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700&family=DM+Sans:wght@300;400;500;600&display=swap\" rel=\"stylesheet\">\n<style>\n:root {\n  --ink:#0a1f14; --forest:#0d3322; --emerald:#145c38; --jade:#1a7a4a;\n  --gold:#c9a84c; --gold-lt:#f0d98a; --cream:#fafaf5; --white:#fff; --muted:#6b7280; --error:#ef4444;\n}\n*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}\nhtml,body{height:100%}\nbody{font-family:'DM Sans',system-ui,sans-serif;background:var(--ink);display:flex;align-items:center;justify-content:center;min-height:100vh;padding:20px}\nbody::before{content:'';position:fixed;inset:0;pointer-events:none;background:radial-gradient(ellipse 70% 60% at 80% 20%,rgba(26,122,74,.2) 0%,transparent 55%),radial-gradient(ellipse 50% 50% at 10% 90%,rgba(201,168,76,.1) 0%,transparent 50%)}\n.card{background:var(--white);border-radius:20px;width:100%;max-width:460px;padding:48px 44px;box-shadow:0 30px 80px rgba(0,0,0,.5);position:relative;z-index:1}\n.logo{display:flex;align-items:center;gap:10px;text-decoration:none;justify-content:center;margin-bottom:32px}\n.logo-icon{width:44px;height:44px;border-radius:10px;background:linear-gradient(135deg,var(--gold),var(--jade));display:flex;align-items:center;justify-content:center;font-size:22px}\n.logo-text{font-family:'Playfair Display',Georgia,serif;font-size:22px;font-weight:700;color:var(--ink)}\n.logo-text span{color:var(--jade)}\n.tabs{display:flex;background:var(--cream);border-radius:10px;padding:4px;margin-bottom:28px}\n.tab{flex:1;padding:10px;border:none;border-radius:8px;background:transparent;cursor:pointer;font-family:'DM Sans',sans-serif;font-size:14px;font-weight:600;color:var(--muted);transition:all .2s}\n.tab.active{background:var(--white);color:var(--ink);box-shadow:0 2px 8px rgba(0,0,0,.1)}\n.form-panel{display:none}\n.form-panel.active{display:block}\n.form-title{font-family:'Playfair Display',serif;font-size:24px;color:var(--ink);margin-bottom:6px}\n.form-sub{font-size:14px;color:var(--muted);margin-bottom:24px;font-weight:300}\n.field{margin-bottom:16px}\n.field label{display:block;font-size:13px;font-weight:600;color:var(--ink);margin-bottom:6px}\n.field input{width:100%;padding:13px 16px;background:var(--cream);border:1.5px solid #e5e7eb;border-radius:8px;font-family:'DM Sans',sans-serif;font-size:15px;color:var(--ink);transition:border-color .2s;outline:none}\n.field input:focus{border-color:var(--jade);background:var(--white);box-shadow:0 0 0 3px rgba(26,122,74,.1)}\n.pw-wrap{position:relative}\n.pw-wrap input{padding-right:46px}\n.toggle-pw{position:absolute;right:14px;top:50%;transform:translateY(-50%);background:none;border:none;cursor:pointer;font-size:18px;color:var(--muted);padding:0;line-height:1}\n.submit-btn{width:100%;padding:15px;background:linear-gradient(135deg,var(--emerald),var(--jade));color:var(--white);border:none;border-radius:8px;font-family:'DM Sans',sans-serif;font-size:16px;font-weight:600;cursor:pointer;transition:all .22s;margin-top:8px;display:flex;align-items:center;justify-content:center;gap:8px}\n.submit-btn:hover{transform:translateY(-2px);box-shadow:0 8px 25px rgba(20,92,56,.4)}\n.submit-btn:disabled{opacity:.6;cursor:not-allowed;transform:none}\n.alert{padding:12px 16px;border-radius:8px;font-size:14px;font-weight:500;margin-bottom:16px;display:none}\n.alert.show{display:block}\n.alert.error{background:#fef2f2;color:var(--error);border:1px solid #fecaca}\n.alert.success{background:#f0fdf4;color:#16a34a;border:1px solid #bbf7d0}\n.footer-note{text-align:center;font-size:13px;color:var(--muted);margin-top:20px}\n.footer-note strong{color:var(--jade);cursor:pointer}\n.footer-note strong:hover{text-decoration:underline}\n.strength-bar{height:4px;border-radius:99px;background:#e5e7eb;margin-top:6px;overflow:hidden}\n.strength-fill{height:100%;border-radius:99px;transition:width .3s,background .3s;width:0}\n.strength-label{font-size:11px;margin-top:4px;font-weight:500}\n@keyframes spin{to{transform:rotate(360deg)}}\n.spinner{width:18px;height:18px;border:2px solid rgba(255,255,255,.3);border-top-color:#fff;border-radius:50%;animation:spin .7s linear infinite;display:none}\n.spinner.show{display:block}\n</style>\n</head>\n<body>\n<div class=\"card\">\n  <a href=\"#\" class=\"logo\">\n    <div class=\"logo-icon\">🛡</div>\n    <span class=\"logo-text\">Land<span>Guard</span> NG</span>\n  </a>\n  <div class=\"tabs\">\n    <button class=\"tab active\" onclick=\"switchTab('login')\">Sign In</button>\n    <button class=\"tab\"        onclick=\"switchTab('register')\">Create Account</button>\n  </div>\n  <div class=\"alert\" id=\"alert\"></div>\n\n  <!-- LOGIN -->\n  <div class=\"form-panel active\" id=\"panel-login\">\n    <h2 class=\"form-title\">Welcome back</h2>\n    <p class=\"form-sub\">Sign in to access LandGuard NG</p>\n    <form id=\"login-form\">\n      <div class=\"field\">\n        <label>Username</label>\n        <input type=\"text\" id=\"l-user\" placeholder=\"Your username\" required>\n      </div>\n      <div class=\"field\">\n        <label>Password</label>\n        <div class=\"pw-wrap\">\n          <input type=\"password\" id=\"l-pass\" placeholder=\"Your password\" required>\n          <button type=\"button\" class=\"toggle-pw\" onclick=\"togglePw('l-pass',this)\">👁</button>\n        </div>\n      </div>\n      <button type=\"submit\" class=\"submit-btn\" id=\"login-btn\">\n        <span>Sign In</span><div class=\"spinner\" id=\"l-spin\"></div>\n      </button>\n    </form>\n    <div class=\"footer-note\">No account? <strong onclick=\"switchTab('register')\">Create one free →</strong></div>\n  </div>\n\n  <!-- REGISTER -->\n  <div class=\"form-panel\" id=\"panel-register\">\n    <h2 class=\"form-title\">Create your account</h2>\n    <p class=\"form-sub\">Join LandGuard NG — it's free</p>\n    <form id=\"register-form\">\n      <div class=\"field\">\n        <label>Full Name</label>\n        <input type=\"text\" id=\"r-name\" placeholder=\"e.g. Chidi Okafor\">\n      </div>\n      <div class=\"field\">\n        <label>Username *</label>\n        <input type=\"text\" id=\"r-user\" placeholder=\"Choose a username\" required>\n      </div>\n      <div class=\"field\">\n        <label>Phone Number *</label>\n        <input type=\"tel\" id=\"r-phone\" placeholder=\"+234 800 000 0000\" required>\n      </div>\n      <div class=\"field\">\n        <label>Password *</label>\n        <div class=\"pw-wrap\">\n          <input type=\"password\" id=\"r-pass\" placeholder=\"Min. 6 characters\" required oninput=\"checkStrength(this.value)\">\n          <button type=\"button\" class=\"toggle-pw\" onclick=\"togglePw('r-pass',this)\">👁</button>\n        </div>\n        <div class=\"strength-bar\"><div class=\"strength-fill\" id=\"s-fill\"></div></div>\n        <div class=\"strength-label\" id=\"s-label\"></div>\n      </div>\n      <div class=\"field\">\n        <label>Confirm Password *</label>\n        <div class=\"pw-wrap\">\n          <input type=\"password\" id=\"r-confirm\" placeholder=\"Repeat your password\" required>\n          <button type=\"button\" class=\"toggle-pw\" onclick=\"togglePw('r-confirm',this)\">👁</button>\n        </div>\n      </div>\n      <button type=\"submit\" class=\"submit-btn\" id=\"register-btn\">\n        <span>Create Account</span><div class=\"spinner\" id=\"r-spin\"></div>\n      </button>\n    </form>\n    <div class=\"footer-note\">Have an account? <strong onclick=\"switchTab('login')\">Sign in →</strong></div>\n  </div>\n</div>\n\n<script>\nfunction switchTab(t) {\n  document.querySelectorAll('.tab').forEach((el,i)=>el.classList.toggle('active',(i===0)===(t==='login')));\n  document.getElementById('panel-login').classList.toggle('active',t==='login');\n  document.getElementById('panel-register').classList.toggle('active',t==='register');\n  hideAlert();\n}\nfunction showAlert(msg,type='error'){const e=document.getElementById('alert');e.textContent=msg;e.className='alert '+type+' show';e.scrollIntoView({behavior:'smooth',block:'nearest'});}\nfunction hideAlert(){document.getElementById('alert').className='alert';}\nfunction togglePw(id,btn){const i=document.getElementById(id);i.type=i.type==='password'?'text':'password';btn.textContent=i.type==='text'?'🙈':'👁';}\nfunction checkStrength(v){\n  const fill=document.getElementById('s-fill'),label=document.getElementById('s-label');\n  let s=0;if(v.length>=6)s++;if(v.length>=10)s++;if(/[A-Z]/.test(v))s++;if(/[0-9]/.test(v))s++;if(/[^A-Za-z0-9]/.test(v))s++;\n  const lvl=[{p:'0%',c:'',t:''},{p:'25%',c:'#ef4444',t:'🔴 Weak'},{p:'50%',c:'#f97316',t:'🟠 Fair'},{p:'75%',c:'#eab308',t:'🟡 Good'},{p:'100%',c:'#22c55e',t:'🟢 Strong'}][Math.min(s,4)];\n  fill.style.width=lvl.p;fill.style.background=lvl.c;label.textContent=lvl.t;label.style.color=lvl.c;\n}\nfunction setLoading(btnId,spinId,on){document.getElementById(btnId).disabled=on;document.getElementById(spinId).classList.toggle('show',on);}\n\ndocument.getElementById('login-form').addEventListener('submit',async e=>{\n  e.preventDefault();hideAlert();setLoading('login-btn','l-spin',true);\n  try{\n    const r=await fetch('/api/auth/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({username:document.getElementById('l-user').value.trim(),password:document.getElementById('l-pass').value})});\n    const d=await r.json();\n    if(r.ok){localStorage.setItem('lg_token',d.token);localStorage.setItem('lg_username',d.username);localStorage.setItem('lg_fullname',d.fullName||d.username);localStorage.setItem('lg_phone',d.phone||'');showAlert('✅ '+d.message,'success');setTimeout(()=>{window.location.href='/'},800);}\n    else showAlert('⚠️ '+d.error);\n  }catch{showAlert('⚠️ Network error. Is the server running?');}\n  finally{setLoading('login-btn','l-spin',false);}\n});\n\ndocument.getElementById('register-form').addEventListener('submit',async e=>{\n  e.preventDefault();hideAlert();\n  const phone=document.getElementById('r-phone').value.trim();\n  const pass=document.getElementById('r-pass').value;\n  const confirm=document.getElementById('r-confirm').value;\n  if(!phone)return showAlert('⚠️ Phone number is required.');\n  if(pass!==confirm)return showAlert('⚠️ Passwords do not match.');\n  if(pass.length<6)return showAlert('⚠️ Password must be at least 6 characters.');\n  setLoading('register-btn','r-spin',true);\n  try{\n    const r=await fetch('/api/auth/register',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({username:document.getElementById('r-user').value.trim(),password:pass,fullName:document.getElementById('r-name').value.trim(),phone})});\n    const d=await r.json();\n    if(r.ok){localStorage.setItem('lg_token',d.token);localStorage.setItem('lg_username',d.username);localStorage.setItem('lg_fullname',d.fullName||d.username);localStorage.setItem('lg_phone',d.phone||'');showAlert('🎉 '+d.message,'success');setTimeout(()=>{window.location.href='/'},900);}\n    else showAlert('⚠️ '+d.error);\n  }catch{showAlert('⚠️ Network error. Is the server running?');}\n  finally{setLoading('register-btn','r-spin',false);}\n});\n\n// Auto-redirect if already logged in\n(async()=>{\n  const t=localStorage.getItem('lg_token');\n  if(t){try{const r=await fetch('/api/auth/me',{headers:{'Authorization':'Bearer '+t}});if(r.ok)window.location.href='/';}catch{}}\n})();\n</script>\n</body>\n</html>\n"
};

let ok = 0, fail = 0;
for (const [name, content] of Object.entries(FILES)) {
  try {
    fs.writeFileSync(path.join(__dirname, name), content, 'utf8');
    console.log('  ✅  ' + name + ' — created');
    ok++;
  } catch(e) {
    console.log('  ❌  ' + name + ' — FAILED: ' + e.message);
    fail++;
  }
}

